SUPER^.operator();

IF (InterlockState<=cInterlockStateError) THEN
	IF (lEnableGradualStop) THEN
		lStopScaling := lStopScaling * lStopFactor;
		IF (ABS(lStopScaling)<cStopScalingZeroThreshold) THEN
			lStopScaling := 0.0;			
		END_IF
	ELSE
		lStopScaling := 0.0;
	END_IF
ELSE
	lStopScaling := 1.0;	
END_IF

IF (ABS(value)<cStopScalingZeroThreshold) THEN
	stop := 0.0;
	RETURN;
END_IF

stop := value * lStopScaling;

IF ((InterlockState<cInterlockStateOveride) AND
	(gManualTemporaryOveride) AND
	(lEnableManualTemporaryOveride)) THEN
	update := value;
	RETURN;
END_IF

update := SUPER^.update(value);

input := input - lOffset;

(* range is symmetrical about zero *)
lInRange := (ABS(input)<ABS(lOuterRegion));

(* output or lValue ranges from lInnerValue down to lOuterValue *)
IF (ABS(input)<=ABS(lInnerRegion)) THEN
	compute := lInnerValue;
	RETURN;
END_IF

IF (ABS(input)>=ABS(lOuterRegion)) THEN
	compute := lOuterValue;
	RETURN;
END_IF

IF (ABS(lInnerRegion)=ABS(lOuterRegion)) THEN
	compute := lInnerValue;
	RETURN;
END_IF

(* scale between lInnerValue and lOuterValue - will generally not be signed *)
compute := lInnerValue + (ABS(input)-ABS(lInnerRegion))/(ABS(lOuterRegion)-ABS(lInnerRegion))*(lOuterValue-lInnerValue);

IF (lCutoutThreshold<=lInitialCutbackThreshold) THEN
	lFactor := 0.0;
ELSE
	lFactor := (-1.0)/(lCutoutThreshold - lInitialCutbackThreshold);
END_IF

lScalingCharge := 1.0;
lScalingDischarge := 1.0;

IF (lValue>lInitialCutbackThreshold) THEN
	threshold := MAX((1.0 + ((lValue-lInitialCutbackThreshold)*lFactor)),lMinimiumThreshold);

	CASE lQualifier OF
		cChargeQualifierBoth:
			lThresholdCharge := threshold;
			lThresholdDischarge := threshold;

		cChargeQualifierCharge:
			lThresholdCharge := threshold;
			lThresholdDischarge := 1.0;

		cChargeQualifierDischarge:
			lThresholdCharge := 1.0;
			lThresholdDischarge := threshold;

		cChargeQualifierNone:
			lThresholdCharge := 1.0;
			lThresholdDischarge := 1.0;
	END_CASE

	IF ((override) OR
		(lQualifier=cChargeQualifierNone)) THEN
		RETURN;
	END_IF

	trigger(FALSE);

	RETURN;
END_IF

lThresholdCharge := 1.0;
lThresholdDischarge := 1.0;

IF (override) THEN
	RETURN;
END_IF

clear();

IF (lValue) THEN
	lInterlockState:=cInterlockStateError;
	lScalingPositive := 0.0;
	lThresholdPositive := 0.0;
	lScalingNegative := 0.0;
	lThresholdNegative := 0.0;

	trigger(FALSE);
END_IF

IF (override) THEN
	RETURN;
END_IF

clear();

IF (lValue) THEN
	lInterlockState:=cInterlockStateErrorNegative;
	lScalingNegative := 0.0;
	lThresholdNegative := 0.0;

	trigger(FALSE);
END_IF

IF (override) THEN
	RETURN;
END_IF

clear();

IF ((lValue<0) AND (lScalingContext.Value<0) AND (lScaling<>1.0)) THEN
	IF (ABS(lScaling)<ABS(lZeroThreshold)) THEN
		lInterlockState := cInterlockStateErrorNegative;
		lScalingNegative := 0.0;
	ELSE
		lInterlockState := cInterlockStateWarning;
		lScalingNegative := lScaling;
	END_IF

	trigger(FALSE);
	RETURN;
END_IF

IF ((lValue>0) AND (lScalingContext.Value>0) AND (lScaling<>1.0)) THEN
	IF (ABS(lScaling)<ABS(lZeroThreshold)) THEN
		lInterlockState  :=cInterlockStateErrorPositive;
		lScalingPositive := 0.0;
	ELSE
		lInterlockState := cInterlockStateWarning;
		lScalingPositive := lScaling;
	END_IF

	trigger(FALSE);
	RETURN;
END_IF

lTimer.operator();

IF (override) THEN
	RETURN;
END_IF

clear();

IF (lValue>lThreshold) THEN
	IF (lTimer.Expired) THEN
		lInterlockState:=cInterlockStateError;
		lScalingPositive := 0.0;
		lThresholdPositive := 0.0;
		lScalingNegative := 0.0;
		lThresholdNegative := 0.0;

		trigger(FALSE);
	END_IF
ELSE
	lTimer.reset();
END_IF

lClientA.initializeState(NopSelf,'',cCCSynchronousInterlock);
lClientB.initializeState(NopSelf,'',cCCSynchronousInterlock);

lTransform.InnerRegion := cInnerRegion;
lTransform.OuterRegion := cOuterRegion;
lTransform.InnerValue := cInnerValue;
lTransform.OuterValue := cOuterValue;

ClientA.ZeroThreshold := cZeroThreshold;
ClientB.ZeroThreshold := cZeroThreshold;

SUPER^.initialize();

lDelta := lInputA.Value - lInputB.Value;

lAverage.Value := (lInputA.Value + lInputB.Value)/2.0;
lAverage.operator();

lScaling := lTransform.compute(lDelta);

lClientA.Value := lDelta * lSignA;
lClientA.Scaling := lScaling;
lClientA.test(FALSE);

lClientB.Value := lDelta * lSignB;
lClientB.Scaling := lScaling;
lClientB.test(FALSE);

SUPER^.operator();

IF (lForceRelaxed) THEN
	relax();
END_IF

lTransform.InnerRegion := cInnerRegionRelaxed;
lTransform.OuterRegion := cOuterRegionRelaxed;
lTransform.InnerValue := cInnerValueRelaxed;
lTransform.OuterValue := cOuterValueRelaxed;

lTransform.InnerRegion := cInnerRegion;
lTransform.OuterRegion := cOuterRegion;
lTransform.InnerValue := cInnerValue;
lTransform.OuterValue := cOuterValue;

lClient.initializeState(NopSelf,'',cCCScaledInterlock);

lTransform.InnerRegion := cInnerRegion;
lTransform.OuterRegion := cOuterRegion;
lTransform.InnerValue := cInnerValue;
lTransform.OuterValue := cOuterValue;

Client.ZeroThreshold := cZeroThreshold;

SUPER^.initialize();

lClient.Value := lInput.Value * lSign;
lClient.Scaling := lTransform.compute(lInput.Value);
lClient.test(FALSE);

SUPER^.operator();

FOR i:=1 TO lMetricCount DO
	lMetricSet[i]^.cycle();
END_FOR

FOR i:=1 TO lMetricCount DO
	lMetricSet[i]^.initialize();
END_FOR

FOR i:=1 TO lMetricCount DO
	lMetricSet[i]^.operator();
END_FOR

IF (metric=0) THEN
	RETURN;
END_IF

IF (lMetricCount>=8) THEN
	gCodeErrorHandler(pMessage:='Metric register overflow');
	RETURN;
END_IF

lMetricCount := lMetricCount + 1;
lMetricSet[lMetricCount] := metric;

FOR i:=1 TO lMetricCount DO
	lMetricSet[i]^.reset();
END_FOR

FOR i:=1 TO lMetricCount DO
	lMetricSet[i]^.start();
END_FOR

FOR i:=1 TO lMetricCount DO
	lMetricSet[i]^.stop();
END_FOR

SUPER^.initialize();

lPower := 0;
lCycleEnergy := 0;
lCycleTime := 0;
lCumulativeEnergy := 0;

lTimeStampPrevious := 0;
lTimeStampCurrent := 0;

lTimeStampPrevious := lTimeStampCurrent;
lTimeStampCurrent := System.Cycle.SystemTimeMicroseconds;

IF (lTimeStampPrevious=0) THEN
	RETURN;
END_IF

lPower := (current * voltage);
lCycleTime := (ULINT_TO_REAL(lTimeStampCurrent)-ULINT_TO_REAL(lTimeStampPrevious))/1000000.0;
lCycleEnergy := lPower* lCycleTime;
lCumulativeEnergy := lCumulativeEnergy + lCycleEnergy;

lPower := 0;
lCycleEnergy := 0;
lCycleTime := 0;
lCumulativeEnergy := 0;

lTimeStampPrevious := System.Cycle.SystemTimeMicroseconds;
lTimeStampCurrent := System.Cycle.SystemTimeMicroseconds;

// foobar make a command

IF ((NOT(__ISVALIDREF(lExternalState))) OR
	(NOT(__ISVALIDREF(lSupplementaryCommand))) OR
	(NOT(__ISVALIDREF(lInternalState))) OR
	(NOT(__ISVALIDREF(lAlarm))) OR
	(NOT(__ISVALIDREF(lMessage))) OR
	(NOT(__ISVALIDREF(lHealthState))) OR
	(NOT(__ISVALIDREF(lHealthAlarm))) OR
	(NOT(__ISVALIDREF(lHealthTrace))) OR
	(NOT(__ISVALIDREF(lSupplementaryState)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lOperatingModeLockRequest.initializeValueObjectOp(OpSelf,'LockReq','Lock operating mode requested','',cValueStyleConfigurable);
lOperatingModeLockRequest.Index := 0;
lOperatingModeLockRequest.InputReference REF= lInternalState;

lOperatingModeRunningRegister.initializeValueObjectOp(OpSelf,'RunningReg','Running operating mode requested','',cValueStyleConfigurable);
lOperatingModeRunningRegister.Index := 1;
lOperatingModeRunningRegister.InputReference REF= lInternalState;

lUMFSRegister.initializeValueObjectOp(OpSelf,'UMFSReg','UMFS registration requested','',cValueStyleConfigurable);
lUMFSRegister.Index := 2;
lUMFSRegister.InputReference REF= lInternalState;

lValidTransmissions.initializeValueObjectOp(OpSelf,'ValidTrnsmssns','Valid transmissions detected','',cValueStyleConfigurable);
lValidTransmissions.Index := 3;
lValidTransmissions.InputReference REF= lInternalState;

lTPDO1Stuffing.initializeValueObjectOp(OpSelf,'TPDO1Stuffing','TPDO1 stuffing bit detected','',cValueStyleConfigurable);
lTPDO1Stuffing.Index := 7;
lTPDO1Stuffing.InputReference REF= lInternalState;

SUPER^.initialize();

lExternalState REF= externalState;
lSupplementaryCommand REF= supplementaryCommand;

lInternalState REF= internalState;
lAlarm REF= alarm;
lMessage REF= message;

lHealthState REF= healthState;
lHealthAlarm REF= healthAlarm;
lHealthTrace REF= healthTrace;

lSupplementaryState REF= supplementaryState;

SUPER^.operator();

lExternalState := 0;
lExternalState := fMergeBitsIntoWord(pWord:=lExternalState,pData:=lSystemState,pStart:=0);
lExternalState := fMergeBitsIntoWord(pWord:=lExternalState,pData:=lOperatingMode,pStart:=4);
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=lUMFSAllow,pStart:=8);
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=lResetDiagnostics,pStart:=9);
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=lResetHardware,pStart:=10);
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=lResetHealth,pStart:=11);
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=lGlobalOverride,pStart:=12);

lExternalStateTarget REF= externalState;
lSupplementaryCommandTarget REF= supplementaryCommand;

lInternalStateTarget REF= internalState;
lAlarmTarget REF= alarm;
lMessageTarget REF= message;

lHealthStateTarget REF= healthState;
lHealthAlarmTarget REF= healthAlarm;
lHealthTraceTarget REF= healthTrace;

lSupplementaryStateTarget REF= supplementaryState;

SUPER^.operator();

(* traffic FROM master PLC *)

lExternalState := lExternalStateTarget;
lSupplementaryCommand := lSupplementaryCommandTarget;

(* traffic to master PLC *)

lInternalStateTarget := lInternalState;
lAlarmTarget := lAlarm;
lMessageTarget := lMessage;

lHealthStateTarget := lHealthState;
lHealthAlarmTarget := lHealthAlarm;
lHealthTraceTarget := lHealthTrace;

lSupplementaryStateTarget := lSupplementaryState;

lVRTriggerCycleOutput.initializeValueReference(lTriggerCycleOutput,NopSelf,'CycleOutput','Power cycle the output','',cValueStyleParameter);

lCausalCycleOutput.initializeState(NopSelf,'',cCCCycleOutput);

lOutput.initializeValueObjectOp(OpSelf,'Output','The output of the object','',cValueStyleConfigurable);

SUPER^.initialize();

lCycleOutputTimer.Enable := TRUE;
lCycleOutputTimer.Period := T#1000MS;
lCycleOutputTimer.initialize();

IF (lTriggerCycleOutput) THEN
	lTriggerCycleOutput := FALSE;
	cycleOutput();
END_IF

lCycleOutputTimer.operator();
IF (NOT(lCycleOutputTimer.Expired)) THEN
	lOutput.Value := lCycleOutputValue;
END_IF

IF (gSystemServices.SystemState.State<lOutputSystemState) THEN
	lOutput.off();
END_IF

lOutput.operator();

SUPER^.operator();

IF (gSystemServices.SystemState.State<lOutputSystemState) THEN
	RETURN;
END_IF

lOutput.Value := NOT(lOutput.Value);

IF (gSystemServices.SystemState.State<lOutputSystemState) THEN
	RETURN;
END_IF

lCycleOutputTimer.reset();
lCycleOutputValue := NOT(lOutput.Value);
lOutput.Value := lCycleOutputValue;

lCausalCycleOutput.trigger(FALSE);

IF (gSystemServices.SystemState.State<lOutputSystemState) THEN
	RETURN;
END_IF

lCycleOutputTimer.reset();
lCycleOutputValue := FALSE;
lOutput.Value := FALSE;

lCausalCycleOutput.trigger(FALSE);

IF (gSystemServices.SystemState.State<lOutputSystemState) THEN
	RETURN;
END_IF

lCycleOutputTimer.reset();
lCycleOutputValue := TRUE;
lOutput.Value := TRUE;

lCausalCycleOutput.trigger(FALSE);

IF (lPackerCount=0) THEN
	gCodeErrorHandler(pMessage:='empty PackChannel');
END_IF

lIndex := 1;

FOR i:=1 TO lPackerCount DO
	lPackerSet[i]^.initialize();
END_FOR

IF (packer=0) THEN
	RETURN;
END_IF

IF (lPackerCount>=16) THEN
	RETURN;
END_IF

lPackerCount := lPackerCount + 1;
lPackerSet[lPackerCount] := packer;

increment();

i:= 0;
WHILE (NOT(lPackerSet[lIndex]^.Enable)) DO
	increment();
	i := i+1;

	IF (i>lPackerCount) THEN
		lIndex := 0;
		RETURN;
	END_IF
END_WHILE

lIndex := lIndex + 1;
IF (lIndex>lPackerCount) THEN
	lIndex := MIN(lPackerCount,1);
END_IF

IF (CurrentPacker.Code=CurrentCode) THEN
	RETURN;
END_IF

// matches request to Code if possible (Code is present and enabled) otherwise defaults to first regardless of whether it is enabled
FOR i:=1 TO lPackerCount DO
	IF ((lPackerSet[i]^.Code=CurrentCode) AND (lPackerSet[i]^.Enable)) THEN
		lIndex := i;
		RETURN;
	END_IF
END_FOR

// assumes always at least one packer in the channel
lIndex := 1;

IF (NOT(lEnable)) THEN
	RETURN;
END_IF

_unpack(packet);
write();
reset();

IF (NOT(lEnable)) THEN
	RETURN;
END_IF

packet.clear();
packet.Code := lCode;

read();
_pack(packet);
reset();

IF (NOT(__ISVALIDREF(source))) THEN
