IF (lLatch) THEN
	Byte1 := Byte1 OR source.Byte1;
	Byte2 := Byte2 OR source.Byte2;
	Byte3 := Byte3 OR source.Byte3;
	Byte4 := Byte4 OR source.Byte4;
	Byte5 := Byte5 OR source.Byte5;
	Byte6 := Byte6 OR source.Byte6;
	Byte7 := Byte7 OR source.Byte7;
	Byte8 := Byte8 OR source.Byte8;	
ELSE
	Byte1 := source.Byte1;
	Byte2 := source.Byte2;
	Byte3 := source.Byte3;
	Byte4 := source.Byte4;
	Byte5 := source.Byte5;
	Byte6 := source.Byte6;
	Byte7 := source.Byte7;
	Byte8 := source.Byte8;	
END_IF

