SubSystem := cSubsystemSecondary;

lModulationSeverity := cSeverityError;
lTargetVoltage := cSecondaryTargetVoltage;

lCurrentState := cRunStateNone;

IF ((lControllerSecondaryPowerSupplyA.CurrentRunState=cRunStateStop) OR
	(lControllerSecondaryPowerSupplyA.CurrentRunState=cRunStateStop)) THEN
	lCurrentState := cRunStateStop;
END_IF

IF ((lControllerSecondaryPowerSupplyA.CurrentRunState=cRunStateStart) OR
	(lControllerSecondaryPowerSupplyA.CurrentRunState=cRunStateStart)) THEN
	lCurrentState := cRunStateStart;
END_IF

IF (lControllerSecondaryPowerSupplyA.CurrentRunState<>lControllerSecondaryPowerSupplyB.CurrentRunState) THEN
	lAlarmRunStateMismatch.trigger(FALSE); // foobar any further action
END_IF

SUPER^.operator();

lRequestedState := cRunStateStop;
lAvailability := 0.0;

IF (gSystemServices.SystemState.State<cSystemStatePreparing) THEN
	RETURN;
END_IF

IF (BMSConnected) THEN
	lRequestedState := cRunStateStart;
END_IF

IF (lCurrentState<>cRunStateStart) THEN
	lAlarmSecondaryNotRunning.trigger(FALSE);

	IF (lAlarmSecondaryNotRunning.Severity>=lModulationSeverity) THEN
		lAlarmSecondaryNotRunningModulation.trigger(FALSE);
	END_IF

	lAlarmSecondaryWaiting.test(FALSE);	
END_IF

lModulation.operator();
lAvailability := MIN(lModulation.ScalingPositive,lModulation.ThresholdPositive);

lControllerSecondaryPowerSupplyA.RequestedRunState := lRequestedState;
lControllerSecondaryPowerSupplyB.RequestedRunState := lRequestedState;

lControllerSecondaryPowerSupplyA.TargetVoltage := lTargetVoltage;
lControllerSecondaryPowerSupplyB.TargetVoltage := lTargetVoltage;

IF (NOT(lValue)) THEN
	lPostTimer.reset();
	lState := t_active_state.cActiveStatePost;
END_IF

IF (lValue) THEN
	lPreTimer.reset();
	lState := t_active_state.cActiveStatePre;
	transitionOutOfInactive();
END_IF

lAllow.initializeValueObjectOp(OpSelf,'Allow','Dependent operations are allowed','',cValueStyleConfigurable);

SUPER^.initialize();

lPreTimer.lEnable := TRUE;
lPreTimer.lPeriod := cActivePreTimeout;
lPreTimer.initialize();

lPostTimer.lEnable := TRUE;
lPostTimer.lPeriod := cActivePostTimeout;
lPostTimer.initialize();

lRegisterActive := FALSE;
lValue := FALSE;
lState := t_active_state.cActiveStateNone;

lValue := lRegisterActive;
lRegisterActive := FALSE;

lPreTimer.operator();
lPostTimer.operator();

CASE (lState) OF
	t_active_state.cActiveStateNone:
		inactive();
	t_active_state.cActiveStatePre:
		pre();
	t_active_state.cActiveStatePost:
		post();
	t_active_state.cActiveStateActive:
		active();
END_CASE

IF (gSystemServices.SystemState.State<>cSystemStateOperational) THEN
	lState := t_active_state.cActiveStateNone;
END_IF

lAllow.Value := ((lState>t_active_state.cActiveStatePre) AND (lAllowPreCondition));

SUPER^.operator();

IF (lValue) THEN
	lState := t_active_state.cActiveStateActive;
	RETURN;
END_IF

IF (lPostTimer.lExpired) THEN
	lState := t_active_state.cActiveStateNone;
END_IF

IF (NOT(lValue)) THEN
	lState := t_active_state.cActiveStateNone;
	RETURN;
END_IF

IF (lPreTimer.lExpired) THEN
	lState := t_active_state.cActiveStateActive;
END_IF

lVRTriggerResetStatistics.initializeValueReference(lTriggerResetStatistics,NopSelf,'ResetStats','Reset all statistics','',cValueStyleTrigger);
lVRTriggerResetHours.initializeValueReference(lTriggerResetHours,NopSelf,'ResetHours','Reset up-time hours','',cValueStyleTrigger);
lVRTriggerResetOperationalHours.initializeValueReference(lTriggerResetOperationalHours,NopSelf,'ResetOpHours','Reset operational hours','',cValueStyleTrigger);
lVRTriggerResetStartCount.initializeValueReference(lTriggerResetStartCount,NopSelf,'ResetStartCnt','Reset plc start count','',cValueStyleTrigger);

lCurrentTime.initializeValueObjectOp(OpSelf,'CurrentTime','Current system time','timestep',cValueStyleConfigurable);

lStartTime.Identifier := t_persistent_id.cPersistentID_StartTimeMicroseconds;
lStartTime.initialize();

lStartCount.Identifier := t_persistent_id.cPersistentID_StartCount;
lStartCount.initialize();

SUPER^.initialize();

lStartCount.Value := lStartCount.Value + 1;

lCurrentTime.operator();

lFirstCycle := TRUE;
lTimeStep := 0;
lPreviousTime := 0;

lIntegralClockTickPrevious := lCurrentTime.Value;
lIntegralClockTick := FALSE;

lCycleTime := sDefaultAverageCycleTime;
lToggleTime := lCurrentTime.Value;

lMaxCycleTime := 0;
lMinCycleTime := 1000000000;

lPreviousStartTime := lStartTime.Value;
lStartTime.Value := lCurrentTime.Value;

lPreviousTime := lCurrentTime.Value;

SUPER^.operator();

IF (lTriggerResetStatistics) THEN
	lTriggerResetStatistics := FALSE;

	lMaxCycleTime := 0;
	lMinCycleTime := 1000000;
END_IF

IF (lTriggerResetHours) THEN
	lTriggerResetHours := FALSE;

	Hours := 0;
END_IF

IF (lTriggerResetOperationalHours) THEN
	lTriggerResetOperationalHours := FALSE;

	OperationalHours := 0;
END_IF

IF (lTriggerResetStartCount) THEN
	lTriggerResetStartCount := FALSE;

	lStartCount.Value := 0;
END_IF

lCycleTime := lCurrentTime.Value - lPreviousTime;
IF (NOT(lFirstCycle)) THEN
	lMinCycleTime := MIN(lMinCycleTime,lCycleTime);
	lMaxCycleTime := MAX(lMaxCycleTime,lCycleTime);

	lAverageCycleTime := REAL_TO_ULINT(ULINT_TO_REAL(lAverageCycleTime)*0.9 + ULINT_TO_REAL(lCycleTime)*0.1);
END_IF
lFirstCycle := FALSE;
lTimeStep := lTimeStep + 1;

lSystemTime := ULINT_TO_STRING(lTimeStep);

IF (lCurrentTime.Value > (lToggleTime + lTogglePeriodMicroseconds)) THEN
	lToggle := NOT(lToggle);
	lToggleTime := lCurrentTime.Value;
END_IF

IF (lCurrentTime.Value > lIntegralClockTickPrevious) THEN
	lIntegralClockTick := TRUE;
	lIntegralClockTickPrevious := lIntegralClockTickPrevious + lIntegralPeriod;
ELSE
	lIntegralClockTick := FALSE;
END_IF

IF (lIntegralRunning) THEN
	lIntegralDuration := lCurrentTime.Value - lIntegralStartTime;
ELSE
	lIntegralStartTime := lCurrentTime.Value;
END_IF
IF (lIntegralReset) THEN
	lIntegralDuration := 0;
	lIntegralReset := FALSE;
END_IF

lCounter := lCounter + 1;

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN	
	RETURN;
END_IF

executeContext^.appendPair('current_time',TIME_TO_STRING(ULINT_TO_TIME(lCurrentTime.Value/1000)),TRUE,TRUE);
executeContext^.appendPair('start_time',TIME_TO_STRING(ULINT_TO_TIME(lStartTime.Value/1000)),TRUE,TRUE);
executeContext^.appendPair('up_time',TIME_TO_STRING(ULINT_TO_TIME((lCurrentTime.Value - lStartTime.Value)/1000)),TRUE,TRUE);
executeContext^.appendPair('system_time',SystemTime,TRUE,TRUE);
executeContext^.appendPair('time_step',gTypeHandler.getTokenForUDINT(lTimeStep),FALSE,TRUE);

IF (gSystemServices.Initialized) THEN
	IF (executeContext^.configureBool(cTokenFailSafeConfig,b,FALSE,0)) THEN
		RETURN;
	END_IF
END_IF

SUPER^.configure(executeContext);

lExecuteContext.Source REF= THIS^;
// lExecuteContextParameterUpdate.Source REF= THIS^; dummy executor: provides context only for direct write out

lAlarmSoftwareCrash.initializeState(NopSelf,'',cACExecutionFailed);

registerOperational(ADR(lClient));

SUPER^.initialize();

lExecuteContext.WriteStream^.IndentStr := '';
lExecuteContext.WriteStream^.NewlineStr := '$n';
lExecuteContext.WriteStream^.RecordInitiatorStr := '{';
lExecuteContext.WriteStream^.RecordTerminatorStr := '}';
lExecuteContext.WriteStream^.clear();
lExecuteContext.EnableExecutor := FALSE;

lExecuteContextParameterUpdate.WriteStream^.IndentStr := '';
lExecuteContextParameterUpdate.WriteStream^.NewlineStr := '$n';
lExecuteContextParameterUpdate.WriteStream^.RecordInitiatorStr := '{';
lExecuteContextParameterUpdate.WriteStream^.RecordTerminatorStr := '}';
lExecuteContextParameterUpdate.WriteStream^.clear();
lExecuteContextParameterUpdate.Command.optionCount := 1;
lExecuteContextParameterUpdate.Command.options[1] := cExecuteOptionParameter;
lExecuteContextParameterUpdate.EnableExecutor := FALSE;

IF (lQueueCount=0) THEN
	getNextExecuteCommand := FALSE;
	RETURN;
END_IF

command := lCommandQueue[1];

FOR i:=1 TO lQueueCount-1 DO
	lCommandQueue[i] := lCommandQueue[i+1];
END_FOR

lQueueCount := lQueueCount - 1;

getNextExecuteCommand := TRUE;

IF (lQueueCount=cCommandQueueMax) THEN
	putCommand := FALSE;
	RETURN;
END_IF

lQueueCount := lQueueCount + 1;
lCommandQueue[lQueueCount] := command;

putCommand := TRUE;

IF (gSystemServices.Initialized) THEN
	IF (executeContext^.configureBool(cTokenFailSafeConfig,b,FALSE,0)) THEN
		RETURN;
	END_IF
END_IF

SUPER^.configure(executeContext);

IF (executeContext=0) THEN
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandDebugMaskAdd)) THEN

	IF (NOT(executeContext^.configureEnum(cEnumTypeDebugMask,cTokenFeature,mask,TRUE,THIS))) THEN
		RETURN;
	END_IF

	gDebugFlags.Value := gDebugFlags.Value OR INT_TO_UINT(mask);
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandDebugMaskDelete)) THEN

	IF (NOT(executeContext^.configureEnum(cEnumTypeDebugMask,cTokenFeature,mask,TRUE,THIS))) THEN
		RETURN;
	END_IF

	gDebugFlags.Value := gDebugFlags.Value AND NOT(INT_TO_UINT(mask));
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandDebugMaskClear)) THEN	
	gDebugFlags.Value := 0;
	RETURN;
END_IF

SUPER^.execute(executeContext);

lVRDebugFlags.initializeValueReference(gDebugFlags,NopSelf,'Debug','System wide debug flags','',cValueStyleParameter);

lVRFailSafeDebugFlags.initializeValueReference(lFailSafeDebugFlags,NopSelf,'FailSafeDebug','Failsafe debug flags','',cValueStyleParameter);
lFailSafeDebugFlags.Identifier := t_persistent_id.cPersistentID_FailSafeDebugFlags;
lFailSafeDebugFlags.initialize();

lVRMachineName.initializeValueReference(lMachineName,NopSelf,'MachineName','Name of the machine','',cValueStyleParameter);
lMachineName.Identifier := t_persistent_id.cPersistentID_MachineName;
lMachineName.initialize();

lRecoveryDetectionStep.Identifier := t_persistent_id.cPersistentID_RecoveryDetectionStep;
lRecoveryDetectionStep.initialize();

lRecoveryDetectionStepActive.Identifier := t_persistent_id.cPersistentID_RecoveryDetectionStepActive;
lRecoveryDetectionStepActive.initialize();

SUPER^.initialize();
SubSystem := cSubsystemMachine;

lRecoveryDetectionPeriods[0] := T#500MS;
lRecoveryDetectionPeriods[1] := T#2500MS;
lRecoveryDetectionPeriods[2] := T#500MS;
lRecoveryDetectionPeriods[3] := T#2500MS;

lRecoveryDetectionTimerLower.Enable := TRUE;
lRecoveryDetectionTimerLower.Period := lRecoveryDetectionPeriods[MIN(lRecoveryDetectionStep.Value,cRecoveryDetectionSteps)];
lRecoveryDetectionTimerLower.initialize();

lRecoveryDetectionTimerUpper.Enable := TRUE;
lRecoveryDetectionTimerUpper.Period := lRecoveryDetectionPeriods[MIN(lRecoveryDetectionStep.Value,cRecoveryDetectionSteps)] + cRecoverDetectionInterval;
lRecoveryDetectionTimerUpper.initialize();

IF (lRecoveryDetectionStepActive.Value) THEN
	lRecoveryDetectionStep.Value := lRecoveryDetectionStep.Value + 1;
	lRecoveryDetectionStepActive.Value := FALSE;
END_IF

IF (lRecoveryDetectionStep.Value>cRecoveryDetectionSteps) THEN
	lRecoveryDetectionStep.Value := 0;
	lRecoveryDetectionSuccess := TRUE;
	gDebugFlags.Value := INT_TO_UINT(cDebugDisableWatchdog);
END_IF

SUPER^.operator();

IF (gSystemServices.PLC.CrashSeverity>3) THEN
	lFailSafeDebugFlags.Value := INT_TO_UINT(cDebugDisableWatchdog);
END_IF

IF (gSystemServices.PLC.CrashSeverity>2) THEN
	gDebugFlags.Value := lFailSafeDebugFlags.Value;
END_IF

IF (lRecoveryDetectionTimerUpper.Enable) THEN
	lRecoveryDetectionTimerLower.operator();
	lRecoveryDetectionTimerUpper.operator();

	lRecoveryDetectionStepActive.Value := ((lRecoveryDetectionTimerLower.Expired) AND
		(NOT(lRecoveryDetectionTimerUpper.Expired)));

	IF ((lRecoveryDetectionTimerLower.Expired) AND
		(lRecoveryDetectionTimerUpper.Expired)) THEN
		lRecoveryDetectionTimerLower.Enable := FALSE;
		lRecoveryDetectionTimerUpper.Enable := FALSE;
		lRecoveryDetectionStep.Value := 0;
	END_IF
END_IF

IF (lPostInitialize) THEN
	postInitialize();
END_IF

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	executeContext^.describeSyntaxExecutable(sCommandDebugMaskAdd);
	executeContext^.describeSyntaxExecutable(sCommandDebugMaskDelete);
	executeContext^.describeSyntaxExecutable(sCommandDebugMaskClear);

	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN	
	RETURN;
END_IF

executeContext^.appendPair('machine_name',lMachineName.Value,TRUE,TRUE);

IF (gSystemServices.Initialized) THEN
	IF (executeContext^.configureBool(cTokenFailSafeConfig,b,FALSE,0)) THEN
		RETURN;
	END_IF
END_IF

SUPER^.configure(executeContext);

IF ((NOT(__ISVALIDREF(lExternalState))) OR
	(NOT(__ISVALIDREF(lSupplementaryCommand))) OR
	(NOT(__ISVALIDREF(lInternalState))) OR
	(NOT(__ISVALIDREF(lReportableState))) OR
	(NOT(__ISVALIDREF(lSupplementaryState)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lOperatingModeLockRequest.initializeValueObjectOp(OpSelf,'LockReq','Lock operating mode requested','',cValueStyleConfigurable);
lOperatingModeLockRequest.Index := 0;
lOperatingModeLockRequest.InputReference REF= lInternalState;

lOperatingModeRunningRegister.initializeValueObjectOp(OpSelf,'RunningReg','Running operating mode requested','',cValueStyleConfigurable);
lOperatingModeRunningRegister.Index := 1;
lOperatingModeRunningRegister.InputReference REF= lInternalState;

lUMFSRegister.initializeValueObjectOp(OpSelf,'UMFSReg','UMFS registration requested','',cValueStyleConfigurable);
lUMFSRegister.Index := 2;
lUMFSRegister.InputReference REF= lInternalState;

lValidTransmissions.initializeValueObjectOp(OpSelf,'ValidTrnsmssns','Valid transmissions detected','',cValueStyleConfigurable);
lValidTransmissions.Index := 3;
lValidTransmissions.InputReference REF= lInternalState;

lTPDO1Stuffing.initializeValueObjectOp(OpSelf,'TPDO1Stuffing','TPDO1 stuffing bit detected','',cValueStyleConfigurable);
lTPDO1Stuffing.Index := 7;
lTPDO1Stuffing.InputReference REF= lInternalState;

SUPER^.initialize();

lExternalState REF= externalState;
lSupplementaryCommand REF= supplementaryCommand;

lInternalState REF= internalState;
lReportableState REF= reportableState;
lSupplementaryState REF= supplementaryState;

SUPER^.operator();

(* traffic FROM master PLC *)

lExternalState := 0;
lExternalState := fMergeBoolIntoWord(pWord:=lExternalState,pData:=gManualTemporaryOveride,pStart:=9);

(* traffic to master PLC *)

u := lReportableState;
FOR i:=0 TO 15 DO
	IF ((UDINT_TO_BOOL(u AND 2#1)) AND
		(lReportable[i]<>0)) THEN
		lReportable[i]^.trigger(FALSE);
	END_IF

	u := SHR(u,1);
END_FOR

IF (index>31) THEN
	RETURN;
END_IF

lReportable[index] := reportable;

SUPER^.operator();

IF (lTriggerWipePersistence) THEN
	lTriggerWipePersistence := FALSE;

	gPersistenceManager.clear();

	defaultPersistence();
	gSystemServices.LocalMachine.defaultPersistence();
END_IF

IF (lTriggerDefaultPersistence) THEN
	lTriggerDefaultPersistence := FALSE;

	defaultPersistence();
	gSystemServices.LocalMachine.defaultPersistence();
END_IF

IF (lTriggerResetSoftwareCrashCount) THEN
	lTriggerResetSoftwareCrashCount := FALSE;

	lSoftwareCrashCount.Value := 0;
END_IF

IF (lCrashDetectionTimer.Enable) THEN
	lCrashDetectionTimer.operator();
	IF (lCrashDetectionTimer.Expired) THEN
		lCrashDetectionTimer.Enable := FALSE;
		lShutdownCode.Value := t_shutdown_code.cShutdownCodeUnknown;
	END_IF
END_IF

IF ((lCrashDetected) OR (lTrapDetected)) THEN
	lAlarmSoftwareCrash.trigger(FALSE);
	gSystemServices.LEDDiagnostic.Code := cLEDCodeSoftwareCrash;
END_IF

IF (lFailSafeModeActive) THEN
	lAlarmFailSafeMode.trigger(FALSE);

	IF (lCrashSeverity.Value>1) THEN
		gSystemServices.LEDDiagnostic.Code := cLEDCodeFailSafeSevere;			
	ELSE
		gSystemServices.LEDDiagnostic.Code := cLEDCodeFailSafe;
	END_IF
END_IF

IF (MaintenanceMode<>lMaintenanceModePrevious) THEN
	lMaintenanceModePrevious := MaintenanceMode;
	setWatchdog();	
END_IF

IF (MaintenanceMode)  THEN
	lAlarmMaintenanceMode.trigger(FALSE);
	gSystemServices.LEDDiagnostic.Code := cLEDCodeMaintenance;
END_IF

IF (fCheckDebugFlags(cDebugDisableWatchdog)<>lDisableWatchDog) THEN
	lDisableWatchDog := NOT(lDisableWatchDog);
	setWatchdog();
END_IF

IF ((lDisableWatchDog) OR (lForceDisableWatchDog)) THEN
	lAlarmWatchdogDisabled.trigger(FALSE);
	gSystemServices.LEDDiagnostic.Code := cLEDCodeWatchDogDisabled;	
END_IF

IF (NOT(lPersistedCommandsStatus)) THEN
	lAlarmPersistedCommands.trigger(FALSE);
END_IF

lVRTriggerWipePersistence.initializeValueReference(lTriggerWipePersistence,NopSelf,'WipePersist','Trigger wipe of persistent memory','',cValueStyleTrigger);
lVRTriggerDefaultPersistence.initializeValueReference(lTriggerDefaultPersistence,NopSelf,'DefaultPersist','Trigger loading default persistent memory','',cValueStyleTrigger);
lVRTriggerResetSoftwareCrashCount.initializeValueReference(lTriggerResetSoftwareCrashCount,NopSelf,'ResetOpSwCrshCnt','Trigger reset software crash count','',cValueStyleTrigger);
lVRMaintenanceMode.initializeValueReference(lMaintenanceMode,NopSelf,'Maintenance','Whether in maintenance mode','',cValueStyleParameter);

lVRTemporaryDisableWatchdog.initializeValueReference(lTemporaryDisableWatchdog,NopSelf,'TmpDsblWatchDog','Temporarily disable watchdog','',cValueStyleParameter);
lTemporaryDisableWatchdog.Identifier := t_persistent_id.cPersistentID_TemporaryDisableWatchdog;
lTemporaryDisableWatchdog.initialize();

lAlarmSoftwareCrash.initializeState(NopSelf,'',cACSoftwareCrash);
lAlarmFailSafeMode.initializeState(NopSelf,'',cACFailSafeMode);
lAlarmMaintenanceMode.initializeState(NopSelf,'',cACMaintenanceMode);
lAlarmWatchdogDisabled.initializeState(NopSelf,'',cACWatchdogDisabled);
lAlarmPersistedCommands.initializeState(NopSelf,'',cACPersistedCommands);

lShutdownCode.Identifier := t_persistent_id.cPersistentID_ShutdownCode;
lShutdownCode.initialize();

lSoftwareCrashCount.Identifier := t_persistent_id.cPersistentID_SoftwareCrashCount;
lSoftwareCrashCount.initialize();

lCrashSeverity.Identifier := t_persistent_id.cPersistentID_CrashSeverity;
lCrashSeverity.initialize();

lDisableWatchDog := fCheckDebugFlags(cDebugDisableWatchdog);

IF (lTemporaryDisableWatchdog.Value) THEN
	lTemporaryDisableWatchdog.Value := FALSE;	
	lForceDisableWatchDog := TRUE;
END_IF

lPersistedCommandCount := 0;
id := t_persistent_id.cPersistentID_CommandRepositoryLower;

FOR i:=1 TO cPersistedCommandCount DO
	lPersistedCommands[i].Identifier := id;
	lPersistedCommands[i].initialize();

	id := id + UINT_TO_INT(lPersistedCommands[i].Blocks);

	IF (lPersistedCommands[i].Valid) THEN
		lPersistedCommandCount := lPersistedCommandCount + 1;
	END_IF
END_FOR

SUPER^.initialize();

lPreviousShutdownCode := lShutdownCode.Value;
lShutdownCode.Value := t_shutdown_code.cShutdownCodeCrashDetected;

lCrashDetected := (lPreviousShutdownCode=t_shutdown_code.cShutdownCodeCrashDetected);
IF (lCrashDetected) THEN		
	lCrashSeverity.Value := lCrashSeverity.Value + 1;
	lSoftwareCrashCount.Value := lSoftwareCrashCount.Value + 1;
ELSE
	lCrashSeverity.Value := 0;
END_IF

lCrashDetectionTimer.Enable := TRUE;
lCrashDetectionTimer.Period := cCrashDetectionPeriod;
lCrashDetectionTimer.initialize();

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	executeContext^.describeSyntaxExecutable(sCommandExport);
	executeContext^.describeSyntaxExecutable(sCommandClear);
	executeContext^.describeSyntaxExecutable(sCommandExecute);

	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN	
	RETURN;
END_IF

executeContext^.appendPair('failsafe_active',gTypeHandler.getTokenForBool(lFailSafeModeActive),FALSE,TRUE);
executeContext^.appendPair('crash_detected',gTypeHandler.getTokenForBool(lCrashDetected),FALSE,TRUE);
executeContext^.appendPair('crash_severity',gTypeHandler.getTokenForUINT(lCrashSeverity.Value),FALSE,TRUE);
executeContext^.appendPair('previous_shutdown',gTypeHandler.getTokenForEnum(cEnumTypeShutdownCode,lPreviousShutdownCode),TRUE,TRUE);
executeContext^.appendPair('watchdog',gTypeHandler.getTokenForBool(NOT((lDisableWatchdog) OR (lForceDisableWatchDog))),FALSE,TRUE);
executeContext^.appendPair('persisted_count',gTypeHandler.getTokenForUINT(lPersistedCommandCount),FALSE,TRUE);
executeContext^.appendPair('persisted_status',gTypeHandler.getTokenForBool(lPersistedCommandsStatus),FALSE,TRUE);

IF (NOT(executeContext^.matchOption(cExecuteOptionVerbose))) THEN
	RETURN;
END_IF

executeContext^.append(', ');
executeContext^.WriteStream^.increaseIndent();
executeContext^.formatWithNewlineIndent();
executeContext^.append('"persisted": [');
executeContext^.WriteStream^.increaseIndent();

FOR i:=1 TO lPersistedCommandCount DO
	IF (NOT(lPersistedCommands[i].Valid)) THEN
		CONTINUE;
	END_IF

	executeContext^.recordInitiatorWithNewlineIndent();
	executeContext^.appendPair('index',gTypeHandler.getTokenForUINT(i),FALSE,FALSE);

	store := lPersistedCommands[i].Value;

	particle := gSystemServices.getParticle(token,store.particle);
	IF (particle=0) THEN
		CONTINUE;
	END_IF

	str := particle^.lIdentity;
	str := CONCAT(str,' ');
	str := CONCAT(str,gTypeHandler.getTokenForEnum(cEnumTypeTokenType,store.command));

	FOR i:=1 TO store.optionCount DO
		str := CONCAT(str,' -');
		str := CONCAT(str,gTypeHandler.getTokenForEnum(cEnumTypeExecuteOption,store.options[i]));
	END_FOR

	FOR i:=1 TO store.argumentCount DO
		str := CONCAT(str,' ');
		str := CONCAT(str,gTypeHandler.getTokenForEnum(cEnumTypeTokenType,store.arguments[i].parameter));
		str := CONCAT(str,'=');
		str := CONCAT(str,store.arguments[i].value);
	END_FOR

	executeContext^.appendPair('command',str,TRUE,TRUE);
	executeContext^.recordTerminator();

	IF (i<lPersistedCommandCount) THEN
		executeContext^.append(', ');		
	END_IF
END_FOR

executeContext^.WriteStream^.decreaseIndent();
executeContext^.append(']');
executeContext^.WriteStream^.decreaseIndent();

IF (gSystemServices.Initialized) THEN
	IF (executeContext^.configureBool(cTokenFailSafeConfig,b,FALSE,0)) THEN
		RETURN;
	END_IF
END_IF

(* eolus
IF (executeContext^.configureX(cTokenRawIndex)) THEN
	index := executeContext^.ParameterAsIndexToken;

	IF (index>gPersistenceManager.IndexMax) THEN
		executeContextFail(executeContext,cExecuteReturnIllegalIndex,TRUE);
		RETURN;
	END_IF

	data := executeContext^.configureUDINT(data);
	IF (NOT(executeContext^.Error)) THEN
		gPersistenceManager.write(index,UDINT_TO_DWORD(data));
	END_IF

	RETURN;
END_IF*)

SUPER^.configure(executeContext);

IF ((lDisableWatchdog) OR (lForceDisableWatchDog)) THEN
	setWatchdogDisabled();
	RETURN;
END_IF

IF ((MaintenanceMode) OR
	(FailSafeModeActive) OR
	(NOT(gSystemServices.Initialized))) THEN
	setWatchdogDebug();
	RETURN;
END_IF

setWatchdogNormal();

IF (executeContext^.matchCommand(sCommandExport)) THEN

	executeContext^.recordInitiator();
	executeContext^.appendPair('identity',lIdentity,TRUE,FALSE);
	executeContext^.append(',"persistent-memory": [');

	comma := FALSE;
	FOR udi:=0 TO gPersistenceManager.IndexMax DO
		executeContext^.appendPair(UDINT_TO_STRING(i),gTypeHandler.getTokenForUDINT(DWORD_TO_UDINT(gPersistenceManager.read(udi))),FALSE,comma);
		comma := TRUE;
	END_FOR

	executeContext^.append(']');
	executeContext^.recordTerminatorWithNewline();

	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandClear)) THEN
	IF (executeContext^.matchOption(cExecuteOptionAll)) THEN
		FOR i:=1 TO cPersistedCommandCount DO
			clearCommand(i);
		END_FOR

		RETURN;
	END_IF

	IF (NOT(executeContext^.configureUINT(cTokenIndex,index,TRUE,0))) THEN
		RETURN;
	END_IF

	IF (index>cPersistedCommandCount) THEN
		executeContextFail(THIS,cExecuteReturnIllegalIndex,TRUE);
		RETURN;
	END_IF

	clearCommand(index);

	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandExecute)) THEN
	IF (executeContext^.matchOption(cExecuteOptionAll)) THEN
		executeAllCommands();

		RETURN;
	END_IF

	IF (NOT(executeContext^.configureUINT(cTokenIndex,index,TRUE,0))) THEN
		RETURN;
	END_IF

	IF (index>cPersistedCommandCount) THEN
		executeContextFail(THIS,cExecuteReturnIllegalIndex,TRUE);
		RETURN;
	END_IF

	executeCommand(index);

	RETURN;
END_IF

SUPER^.execute(executeContext);

FOR i:=1 TO cPersistedCommandCount DO
	clearCommand(i);
END_FOR

executeCommand := FALSE;

IF (index>cPersistedCommandCount) THEN
	RETURN;
END_IF

store := lPersistedCommands[index].Value;

command.particle := gSystemServices.getParticle(token,store.particle);
IF (command.particle=0) THEN
	RETURN;
END_IF

command.command := store.command;
command.argumentCount := store.argumentCount;
command.arguments := store.arguments;
command.optionCount := store.optionCount;
command.options := store.options;

executeCommand := gSystemServices.Executor.putCommand(command);

lPersistedCommandsStatus := TRUE;

FOR i:=1 TO cPersistedCommandCount DO
	IF (NOT(executeCommand(i))) THEN
		lPersistedCommandsStatus := FALSE;
	END_IF
END_FOR

executeAllCommands := lPersistedCommandsStatus;

IF ((command.particle=0) OR
	(lPersistedCommandCount=cPersistedCommandCount)) THEN
	persistCommand := FALSE;
	RETURN;
END_IF

store.particle := command.particle^.lParticleId;

store.argumentCount := command.argumentCount;
store.arguments := command.arguments;
store.command := command.command;
store.optionCount := command.optionCount;
store.options := command.options;

FOR i:=1 TO store.optionCount DO
	IF (store.options[i]=cExecuteOptionPersist) THEN		
		store.optionCount := store.optionCount - 1;
		FOR j:=i TO store.optionCount DO
			store.options[j] := store.options[j+1];
		END_FOR	
	END_IF
END_FOR

FOR i:=1 TO cPersistedCommandCount DO
	IF (NOT(lPersistedCommands[i].Valid)) THEN
		lPersistedCommands[i].Value := store;
		lPersistedCommandCount := lPersistedCommandCount + 1;

		persistCommand := TRUE;
		RETURN;
	END_IF
END_FOR

persistCommand := FALSE;

IF (index>cPersistedCommandCount) THEN
	RETURN;
END_IF

store.particle := 0;
store.command := 0;
store.optionCount := 0;
store.argumentCount := 0;

IF ((lPersistedCommands[index].Valid) AND
	(lPersistedCommandCount>0)) THEN
	lPersistedCommandCount := lPersistedCommandCount - 1;
END_IF

lPersistedCommands[index].Value := store;

lCausalSyncState.initializeState(NopSelf,'',cCCSyncState);

lMasterSystemState.EnumType := cEnumTypeSystemState;
lMasterSystemState.initializeValueObject(NopSelf,'Master','System state of master','',cValueStyleConfigurable);

SUPER^.initialize();

lAutomaticStart := TRUE;

lMasterSystemState.operator();
IF ((lMasterSystemState.Value<=lLowerSyncState) OR
	(lMasterSystemState.Value>lUpperSyncState)) THEN
	transitionForceMax(lMasterSystemState.Value,ADR(lCausalSyncState),lCausalSyncState.Override);
END_IF

SUPER^.operator();

lReadStream.clear();
lReadStream.appendPtr(ADR(str));
lReadStream.initializeParsing();

lWriteStream.clear();
//eolus IF ((NOT(parse(ADR(lReadStream),ADR(lWriteStream),TRUE))) OR
//eolus 	(lReadStream.CurrentToken=cTokenError) OR 
//eolus 	(lReadStream.CurrentToken=cTokenOverflow)) THEN
//eolus 	gCodeErrorHandler(pMessage:='Syntax error - bad string');
//eolus END_IF

SUPER^.recurse(executeContext);

IF (NOT(executeContext^.matchOption(cExecuteOptionSubsystems))) THEN	
	RETURN;
END_IF

FOR i:=1 TO lSubsystemCount DO
	lSubsystemSet[i]^.recurse(executeContext);
END_FOR

lFeature := false;

SUPER^.initialize();

FOR i:=1 TO lSubsystemCount DO
	IF (lSubsystemSet[i]^.lParticleId=0) THEN
		lSubsystemSet[i]^.initialize();
	END_IF
END_FOR

IF (lTriggerClearFailSafeMode) THEN
	lTriggerClearFailSafeMode := FALSE;
	clearFailSafeMode();
END_IF

IF (lInitializationStage<1) THEN
	RETURN;
END_IF

FOR i:=1 TO lSubsystemCount DO
	IF (lSubsystemSet[i]^.lProceed) THEN
		lSubsystemSet[i]^.operator();
	END_IF
END_FOR

SUPER^.operator();

IF (NOT(lInitialized)) THEN
	gSystemServices.LEDDiagnostic.Code := cLEDCodeStartup;
END_IF

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN	
	RETURN;
END_IF

executeContext^.appendPair('failsafe_active',gTypeHandler.getTokenForBool(PLC.FailSafeModeActive),FALSE,TRUE);
executeContext^.appendPair('systemstate',gTypeHandler.getTokenForEnum(cEnumTypeSystemState,SystemState.State),TRUE,TRUE);
executeContext^.appendPair('initialized',gTypeHandler.getTokenForBool(lInitialized),FALSE,TRUE);
executeContext^.appendPair('initialization_stage',SINT_TO_STRING(lInitializationStage),FALSE,TRUE);

IF (NOT(executeContext^.matchOption(cExecuteOptionChildren))) THEN
	RETURN;
END_IF

executeContext^.append(', ');
executeContext^.WriteStream^.increaseIndent();
executeContext^.formatWithNewlineIndent();
executeContext^.append('"subsystems": [');
executeContext^.WriteStream^.increaseIndent();

FOR i:=1 TO lSubsystemCount DO
	executeContext^.recordInitiatorWithNewlineIndent();
	executeContext^.appendPair('identity',lSubsystemSet[i]^.lIdentity,TRUE,FALSE);
	executeContext^.appendPair('type',lSubsystemSet[i]^.TypeToken,TRUE,TRUE);
	executeContext^.appendPair('subsystem',gTypeHandler.getTokenForEnum(cEnumTypeSubsystem,lSubsystemSet[i]^.SubSystem),TRUE,TRUE);
	executeContext^.recordTerminator();

	IF (i<lSubsystemCount) THEN
		executeContext^.append(', ');		
	END_IF
END_FOR

executeContext^.WriteStream^.decreaseIndent();
executeContext^.append(']');
executeContext^.WriteStream^.decreaseIndent();

//System REF= THIS^;

IF ((NOT(__ISVALIDREF(gSystemServices))) OR
	(NOT(__ISVALIDREF(_LocalMachine))) OR
	(NOT(__ISVALIDREF(_LEDDiagnostic))) OR
	(NOT(__ISVALIDREF(_ReportableChannelManager))) OR
	(NOT(__ISVALIDREF(_Executor))) OR
	(NOT(__ISVALIDREF(_Cycle))) OR
	(NOT(__ISVALIDREF(_PLC))) OR
	(NOT(__ISVALIDREF(_SystemState)))) THEN
	gCodeErrorHandler(pMessage:='null reference in system');
END_IF	

lVRTriggerClearFailSafeMode.initializeValueReference(lTriggerClearFailSafeMode,NopSelf,'ClearFailSafe','Trigger clearing failsafe mode','',cValueStyleTrigger);

initialize();

IF (gCodeErrorHandler.lState) THEN
	RETURN;
END_IF

lInitializationStage := 1;

IF (gCodeErrorHandler.lState) THEN
	RETURN;
END_IF

CASE (lInitializationStage) OF
	-1:
		preInitialize();

	0:
		initializeStage0();

	1:
		initializeStage1();

	2:
		initializeStage2();

	3:
		initializeStage3();

	4:
		postInitialize();
END_CASE

initialize();

token := 'true';
//eolus configure(sTokenFailSafeConfig,token,TRUE,0);

IF (gCodeErrorHandler.lState) THEN
	RETURN;
END_IF

lInitializationStage := 2;

initialize();

IF (gSystemServices.PLC.CrashSeverity<=4) THEN
	token := 'true';
	//eolus configure(sTokenFailSafeConfig,token,TRUE,0);
END_IF

IF (gCodeErrorHandler.lState) THEN
	RETURN;
END_IF

lInitializationStage := 3;

initialize();

IF (gCodeErrorHandler.lState) THEN
	RETURN;
END_IF

lInitializationStage := 4;

IF (gSystemServices.Initialized) THEN
	IF (executeContext^.configureBool(cTokenFailSafeConfig,b,FALSE,0)) THEN
		RETURN;
	END_IF
END_IF

SUPER^.configure(executeContext);

gTypeHandler.initialize();

gDebugFlags.Identifier := t_persistent_id.cPersistentID_DebugFlags;
gDebugFlags.initialize();

lInitializationStage := 0;
lFailSafeConfig := TRUE;

IF (gDebugFlags.Value := 16#FFFF) THEN
	gDebugFlags.Value := 0;
END_IF

initialize();

IF ((PLC.CrashSeverity>0) AND (fCheckDebugFlags(cDebugEnableFailSafeOnCrash))) THEN
	gSystemServices.FailSafeMode := TRUE;
END_IF

PLC.setWatchdog();
PLC.executeAllCommands();

IF (gCodeErrorHandler.lState) THEN
	RETURN;
END_IF

lInitializationStage := 5;
lInitialized := TRUE;

FOR i:=1 TO lSubsystemCount DO
	IF (id>0) THEN
		particle := lSubsystemSet[i]^.getParticle(name,id);
		IF (particle<>0) THEN
			getParticle := particle;
			RETURN;
		END_IF
	ELSE
		IF (strcmp(name,lSubsystemSet[i]^.lName)) THEN
			getParticle := lSubsystemSet[i];
			RETURN;
		END_IF		
	END_IF
END_FOR

getParticle := SUPER^.getParticle(name,id);

IF (particle=0) THEN
	RETURN;
END_IF

IF (lSubsystemCount>=cSubsystemSetMax) THEN
	gCodeErrorHandler(pMessage:='SubsystemSet overflow');
	RETURN;
END_IF

lSubsystemCount := lSubsystemCount + 1;
lSubsystemSet[lSubsystemCount] := particle;
particle^.Parent := 0;
particle^.lFeature := FALSE;

lState.EnumType := cEnumTypeSystemState;
lState.initializeValueObject(NopSelf,'State','System state','',cValueStyleConfigurable);

lSystemControlTrace.initializeEvent(NopSelf,'',cECSystemControl);
lAllowUpTrace.initializeEvent(NopSelf,'',cECAllowUpState);
lAllowDownTrace.initializeEvent(NopSelf,'',cECAllowDownState);
lForceMaxTrace.initializeEvent(NopSelf,'',cECForceMaxState);
lNextStateTrace.initializeEvent(NopSelf,'',cECNextState);

lTransitionInitializedStandby.initializeEvent(NopSelf,'',cECTransitionInitializedStandby);
lTransitionStandbyPreparing.initializeEvent(NopSelf,'',cECTransitionStandbyPreparing);
lTransitionStandbyInitialized.initializeEvent(NopSelf,'',cECTransitionStandbyInitialized);
lTransitionPreparingPreOperational.initializeEvent(NopSelf,'',cECTransitionPreparingPreOperational);
lTransitionPreparingCharging.initializeEvent(NopSelf,'',cECTransitionPreparingCharging);
lTransitionPreparingStandby.initializeEvent(NopSelf,'',cECTransitionPreparingStandby);
lTransitionChargingPreparing.initializeEvent(NopSelf,'',cECTransitionChargingPreparing);
lTransitionPreOperationalPreparing.initializeEvent(NopSelf,'',cECTransitionPreOperationalPreparing);
lTransitionPoweringUpGoOperational.initializeEvent(NopSelf,'',cECTransitionPoweringUpGoOperational);
lTransitionGoOperationalOperational.initializeEvent(NopSelf,'',cECTransitionGoOperationalOperational);
lTransitionExitOperationalPoweringDown.initializeEvent(NopSelf,'',cECTransitionExitOperationalPoweringDown);
lTransitionPoweringDownPreOperational.initializeEvent(NopSelf,'',cECTransitionPoweringDownPreOperational);

lCausalAutomaticStart.initializeState(NopSelf,'',cCCAutomaticStart);

SUPER^.initialize();

// lTransitionEstopState := cSystemStateInitialized;
lTransitionEstopState := cSystemStatePreparing;

lPoweringUpTimer.initialize();
lPoweringUpTimer.Enable := TRUE;
lPoweringUpTimer.Period := cPoweringUpPeriod;

lExitOperationalTimer.initialize();
lExitOperationalTimer.Enable := TRUE;
lExitOperationalTimer.Period := cExitOperationalPeriod;

lState.Value := cSystemStateInitialized;
lPreviousState := State;

lTransitionFlag := FALSE;
lChargingEnabled := FALSE;

lTransitionInitializedStandby.Suppress := FALSE;
lTransitionStandbyPreparing.Suppress := false;
lTransitionStandbyInitialized.Suppress := false;
lTransitionPreparingPreOperational.Suppress := false;
lTransitionPreparingCharging.Suppress := false;
lTransitionPreparingStandby.Suppress := false;
lTransitionChargingPreparing.Suppress := false;
lTransitionPreOperationalPreparing.Suppress := false;
lTransitionPoweringUpGoOperational.Suppress := false;
lTransitionGoOperationalOperational.Suppress := false;
lTransitionExitOperationalPoweringDown.Suppress := false;
lTransitionPoweringDownPreOperational.Suppress := false;

lSystemControlTrace.operator();
lSystemControlTrace.apply();

lAllowUpTrace.operator();
lAllowDownTrace.operator();

IF (State<=cSystemStateStandby) THEN
	gSystemServices.LEDDiagnostic.Code := cLEDCodeStandby;
ELSE
	gSystemServices.LEDDiagnostic.Code := cLEDCodeNormal;	
END_IF

CASE State OF
	cSystemStateNone:
		;
	cSystemStateInitialized:
		stateInitialized();
	cSystemStateStandby:
		stateStandby();
	cSystemStatePreparing:
		statePreparing();
	cSystemStateCharging:
		stateCharging();
	cSystemStatePreOperational:
		statePreOperational();
	cSystemStatePoweringDown:
		statePoweringDown();
	cSystemStatePoweringUp:
		statePoweringUp();
	cSystemStateGoOperational:
		stateGoOperational();
	cSystemStateExitOperational:
		stateExitOperational();
	cSystemStateOperational:
		stateOperational();
END_CASE

lForceMaxTrace.operator();

IF (lNextStateTrace.check(State)>lForceMaxTrace.State) THEN
	transitionNextState(lForceMaxTrace.State,ADR(lForceMaxTrace),lForceMaxTrace.Override);
END_IF

lNextStateTrace.operator();
lPreviousState := lState.Value;
lState.Value := lNextStateTrace.update(State);
lState.operator();

lStateCounterCharging := lStateCounterCharging + 1;

(* up - no automatic transitions *)
;

(* down *)
IF (lForceMaxTrace.State<cSystemStateCharging) THEN
	lTransitionChargingPreparing.trigger(FALSE);
	transitionNextState(cSystemStatePreparing,ADR(lTransitionChargingPreparing),FALSE);
END_IF

lStateCounterExitOperational := lStateCounterExitOperational + 1;

lExitOperationalTimer.operator();

(* up - no automatic transitions *)

(* down *)
IF ((lAllowDownTrace.State<=cSystemStatePoweringDown) AND
	(lExitOperationalTimer.Expired)) THEN
	lTransitionExitOperationalPoweringDown.trigger(FALSE);
	transitionNextState(cSystemStatePoweringDown,ADR(lTransitionExitOperationalPoweringDown),FALSE);
END_IF

lStateCounterGoOperational := lStateCounterGoOperational + 1;

(* up *)
IF (lAllowUpTrace.State>=cSystemStateOperational) THEN
	lTransitionGoOperationalOperational.trigger(FALSE);
	transitionNextState(cSystemStateOperational,ADR(lTransitionGoOperationalOperational),FALSE);
END_IF

(* down - no automatic down *)

lStateCounterInitialized := lStateCounterInitialized + 1;

(* up *)
IF (lAllowUpTrace.State>=cSystemStateStandby) THEN
	lTransitionInitializedStandby.trigger(FALSE);
	transitionNextState(cSystemStateStandby,ADR(lTransitionInitializedStandby),FALSE);
END_IF

(* no down *)

IF (lTransitionFlag) THEN
	lInitializedCounter := lInitializedCounter + 1;
END_IF

lStateCounterOperational := lStateCounterOperational + 1;

lExitOperationalTimer.reset();

(* up - no automatic transitions *)
;

(* down - no automatic transitions *)
;

lStateCounterPoweringDown := lStateCounterPoweringDown + 1;

(* up - no automatic transitions *)

(* down *)
IF (lAllowDownTrace.State<=cSystemStatePreOperational) THEN
	lTransitionPoweringDownPreOperational.trigger(FALSE);
	transitionNextState(cSystemStatePreOperational,ADR(lTransitionPoweringDownPreOperational),FALSE);
END_IF

lStateCounterPoweringUp := lStateCounterPoweringUp + 1;

lPoweringUpTimer.operator();

(* up *)
IF ((lAllowUpTrace.State>=cSystemStateGoOperational) AND
	(lPoweringUpTimer.Expired)) THEN
	lTransitionPoweringUpGoOperational.trigger(FALSE);
	transitionNextState(cSystemStateGoOperational,ADR(lTransitionPoweringUpGoOperational),FALSE);
END_IF

(* down - no automatic down *)

lStateCounterPreOperational := lStateCounterPreOperational + 1;

lPoweringUpTimer.reset();

(* up *)
IF (lAutomaticStart) THEN
	lCausalAutomaticStart.trigger(FALSE);
	transitionStart(cSystemStateOperational,ADR(lCausalAutomaticStart),lCausalAutomaticStart.Override);
END_IF

(* down *)
IF (lForceMaxTrace.State<cSystemStatePreOperational) THEN
	lTransitionPreOperationalPreparing.trigger(FALSE);
	transitionNextState(cSystemStatePreparing,ADR(lTransitionPreOperationalPreparing),FALSE);
END_IF

lStateCounterPreparing := lStateCounterPreparing + 1;

(* up *)
IF (lAllowUpTrace.State>=cSystemStatePreOperational) THEN
	lTransitionPreparingPreOperational.trigger(FALSE);
	transitionNextState(cSystemStatePreOperational,ADR(lTransitionPreparingPreOperational),FALSE);
END_IF

IF ((lAllowUpTrace.State=cSystemStateCharging) AND
	(lChargingEnabled)) THEN
	lTransitionPreparingCharging.trigger(FALSE);
	transitionNextState(cSystemStateCharging,ADR(lTransitionPreparingCharging),FALSE);
END_IF

(* down *)
IF (lForceMaxTrace.State<cSystemStatePreparing) THEN
	lTransitionPreparingStandby.trigger(FALSE);
	transitionNextState(cSystemStateStandby,ADR(lTransitionPreparingStandby),FALSE);
END_IF

lStateCounterStandby := lStateCounterStandby + 1;

(* up *)
IF (lAllowUpTrace.State>=cSystemStatePreparing) THEN
	lTransitionStandbyPreparing.trigger(FALSE);
	transitionNextState(cSystemStatePreparing,ADR(lTransitionStandbyPreparing),FALSE);
END_IF

(* down *)
IF (lForceMaxTrace.State<cSystemStateStandby) THEN
	lTransitionStandbyInitialized.trigger(FALSE);
	transitionNextState(cSystemStateInitialized,ADR(lTransitionStandbyInitialized),FALSE);
END_IF

IF (State>cSystemStatePreOperational) THEN
	IF (State>cSystemStatePoweringUp) THEN		
		transitionNextState(cSystemStateExitOperational,reportable,override);
		transitionForceMax(cSystemStateExitOperational,reportable,override);

	ELSIF (State>cSystemStatePreOperational) THEN		
		transitionNextState(cSystemStatePoweringDown,reportable,override);
		transitionForceMax(cSystemStatePoweringDown,reportable,override);
	END_IF

	RETURN;
END_IF

transitionAllowUp(allowable,reportable,override);
transitionForceMax(allowable,reportable,override);

IF (NOT(lInteractive)) THEN
	RETURN;
END_IF

str := CONCAT('Connected to <',
	CONCAT(gSystemServices.LocalMachine.MachineName,
	CONCAT('> at time <',
	CONCAT(gSystemServices.Cycle.SystemTime,'>$r$n'))));

lConnection^.write(ADR(str[0]),INT_TO_UINT(LEN(str)) + 1);

prompt();

IF (NOT(lConnection^.read(ADR(lReadStream)))) THEN
	RETURN;
END_IF

lCount := lCount + 1;

IF (NOT(lEnabled)) THEN
	RETURN;
END_IF

lReadStream.terminateWithNewline();
lConnection^.write(lReadStream.Buffer,lReadStream.Length);
prompt();

lExecuteContext.operator();
lConnection^.write(lExecuteContext.WriteStream^.Buffer,lExecuteContext.WriteStream^.Length);

IF ((lParsingComplete) OR
	(NOT(lEnabled))) THEN
	IF (NOT(lConnection^.read(ADR(lReadStream)))) THEN
		RETURN;
	END_IF

	lCount := lCount + 1;

	IF (NOT(lEnabled)) THEN
		clear();
		RETURN;
	END_IF

	lParsingComplete := FALSE;
	lReadStream.initializeParsing();
END_IF

IF (lPromptRequired) THEN
	prompt();
	lPromptRequired := FALSE;
END_IF

getNextExecuteCommand := parse(command);

IF (NOT(getNextExecuteCommand)) THEN
	RETURN;
END_IF

lPromptRequired := TRUE;

if (lExecuteContext.Error) then
	RETURN;
END_IF

IF ((command.particle=0) OR
	(command.command=cTokenNone)) THEN
	lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxIncompleteRequest;
	lExecuteContext.Error := TRUE;
END_IF

parse := FALSE;

command.particle := 0;
command.command := cTokenNone;
command.argumentCount := 0;
command.optionCount := 0;

IF (lParsingComplete) THEN
	RETURN;
END_IF

name := ADR(gSystemServices);

FOR lTokensParsedCount:=0 TO cParseMaxTokens DO
	parseTokenType := lReadStream.getNextToken(ADR(token));

	IF ((parseTokenType=cParseTokenNone) OR
		(parseTokenType=cParseTokenFinished)) THEN
		lParsingComplete := TRUE;
		RETURN;		
	END_IF

	IF (parseTokenType=cParseTokenTerminator) THEN
		RETURN;		
	END_IF

	parse := TRUE;

	IF (parseTokenType=cParseTokenOverflow) THEN
		lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxTokenOverflow;
		lExecuteContext.Error := TRUE;
		lReadStream.skipOverError();
		RETURN;		
	END_IF

	IF (parseTokenType=cParseTokenError) THEN
		lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntax;
		lExecuteContext.Error := TRUE;
		lReadStream.skipOverError();
		RETURN;		
	END_IF

	IF ((parameterPending) AND
		(parseTokenType<>cParseTokenName) AND
		(parseTokenType<>cParseTokenSimple)) THEN
		lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxIncompleteParameter;
		lExecuteContext.Error := TRUE;
		lReadStream.skipOverError();
		RETURN;						
	END_IF

	IF ((namePending) AND
		(parseTokenType<>cParseTokenName) AND
		(parseTokenType<>cParseTokenSimple)) THEN
		lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxIncompleteName;
		lExecuteContext.Error := TRUE;
		lReadStream.skipOverError();
		RETURN;						
	END_IF

	IF ((command.particle=0) AND
		(parseTokenType<>cParseTokenName) AND
		(parseTokenType<>cParseTokenSimple)) THEN
		lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxStartWithName;
		lExecuteContext.Error := TRUE;
		lReadStream.skipOverError();
		RETURN;						
	END_IF

	IF ((command.command=cTokenNone) AND
		(parseTokenType<>cParseTokenName) AND
		(parseTokenType<>cParseTokenSimple)) THEN
		lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxCommandAfterName;
		lExecuteContext.Error := TRUE;
		lReadStream.skipOverError();
		RETURN;						
	END_IF

	CASE parseTokenType OF
		cParseTokenName:
			name := getParticle(name,token);
			IF (name=0) THEN
				lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxUnkownName;
				lExecuteContext.Error := TRUE;
				lReadStream.skipOverError();
				RETURN;	
			END_IF

			namePending := TRUE;						

		cParseTokenSimple:
			IF (command.particle=0) THEN
				command.particle := getParticle(name,token);

				IF (command.particle=0) THEN
					lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxUnkownName;
					lExecuteContext.Error := TRUE;
					lReadStream.skipOverError();
					RETURN;	
				END_IF								

				namePending := FALSE;
				name := ADR(gSystemServices);

				CONTINUE;
			END_IF

			IF (parameterPending) THEN
				IF (namePending) THEN
					name := getParticle(name,token);

					IF (name=0) THEN
						lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxUnkownNameForParameter;
						lExecuteContext.Error := TRUE;
						lReadStream.skipOverError();
						RETURN;	
					END_IF

					value := gTypeHandler.getTokenForUINT(name^.lParticleId);

					namePending := FALSE;
					name := ADR(gSystemServices);
				ELSE
					value := token;
				END_IF								

				IF (command.argumentCount>=cExecuteArgumentListCount) THEN
					lExecuteContext.ExecuteReturn := cExecuteReturnTooManyArguments;
					lExecuteContext.Error := TRUE;
					lReadStream.skipOverError();
					RETURN;				
				END_IF

				command.argumentCount := command.argumentCount + 1;
				command.arguments[command.argumentCount].parameter := parameter;
				command.arguments[command.argumentCount].value := value;
				command.arguments[command.argumentCount].processed := FALSE;

				CONTINUE;
			END_IF			

			IF (command.command<>cTokenNone) THEN
				lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxDuplicateCommands;
				lExecuteContext.Error := TRUE;
				lReadStream.skipOverError();
				RETURN;				
			END_IF

			IF (NOT(gTypeHandler.getEnumFromToken(cEnumTypeTokenType,token,command.command))) THEN
				lExecuteContext.ExecuteReturn := cExecuteReturnUnknownCommand;
				lExecuteContext.Error := TRUE;
				lReadStream.skipOverError();
				RETURN;
			END_IF			

		cParseTokenParameter:	
			IF (NOT(gTypeHandler.getEnumFromToken(cEnumTypeTokenType,token,parameter))) THEN
				lExecuteContext.ExecuteReturn := cExecuteReturnUnknownParameter;
				lExecuteContext.Error := TRUE;
				lReadStream.skipOverError();
				RETURN;						
			END_IF

			parameterPending := TRUE;

		cParseTokenOption:
			IF (NOT(gTypeHandler.getEnumFromToken(cEnumTypeExecuteOption,token,option))) THEN
				lExecuteContext.ExecuteReturn := cExecuteReturnUnknownOption;
				lExecuteContext.Error := TRUE;
				lReadStream.skipOverError();
				RETURN;
			END_IF

			IF (command.optionCount>=cExecuteOptionListCount) THEN
				lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxTooManyOptions;
				lExecuteContext.Error := TRUE;
				lReadStream.skipOverError();
				RETURN;				
			END_IF

			command.optionCount := command.optionCount + 1;
			command.options[command.optionCount] := option;
	END_CASE
END_FOR

lExecuteContext.ExecuteReturn := cExecuteReturnExecutionSyntaxUnbounded;
lExecuteContext.Error := TRUE;
lReadStream.skipOverError();

IF (particle=0) THEN
	getParticle := 0;
	RETURN;
END_IF

IF (NOT(splitFQN(fqn,tokens,count))) THEN
	getParticle := 0;
	RETURN;
END_IF

IF (count=0) THEN
	getParticle := 0;
	RETURN;
END_IF

IF (count=1) THEN
	getParticle := particle^.getParticle(tokens[1],0);
	RETURN;
END_IF

IF (particle<>ADR(gSystemServices)) THEN
	getParticle := 0;
	RETURN;	
END_IF

IF (NOT(tokens[1]=gNameSpace)) THEN
	getParticle := 0;
	RETURN;
END_IF

FOR i:=2 TO count DO
	particle := particle^.getParticle(tokens[i],0);

	IF (particle=0) THEN
		getParticle := 0;
		RETURN;		
	END_IF	
END_FOR

getParticle := particle;

registerOperational(ADR(lClient));

SUPER^.initialize();

lExecuteContext.WriteStream^.IndentStr := '';
lExecuteContext.WriteStream^.NewlineStr := '$n';
lExecuteContext.WriteStream^.RecordInitiatorStr := '{';
lExecuteContext.WriteStream^.RecordTerminatorStr := '}';

lExecuteContext.WriteStream^.clear();

lCycleIndex := 0;

lCycleTimer.initialize();
lCycleTimer.Enable := TRUE;
lCycleTimer.Period := cCyclePeriod;

lCycleTimer.operator();
IF (lCycleTimer.Expired) THEN
	lCycleTimer.reset();
	lCycleIndex := 1;
END_IF

i := 0;
WHILE ((lCycleIndex>0) AND (i<lCycleCount)) DO
	i := i + 1;

	state := lReportableChannelManager^.lReportableStateManager.cycle(lChannelMask,ADR(lCycleIndex),FALSE);
	IF (state<>0) THEN
		_reportState(state,FALSE);	
	END_IF
END_WHILE

IF (gSystemServices.Cycle.IntegralClockTick) THEN
	lVolumeMbs := UDINT_TO_REAL(lVolumeBits)/1000000.0;
	lVolumeBits := 0;
END_IF

SUPER^.operator();

length := lExecuteContext.WriteStream^.Length;

IF (lEnabled) THEN
	lClient.write(lExecuteContext.WriteStream^.Buffer,length);
	lVolumeBits := lVolumeBits + length;
END_IF

lExecuteContext.WriteStream^.clear();

(*lStream.newline();
lStream.append('timestep <');
lStream.append(System.Cycle.SystemTime);
lStream.append('> state <');
lStream.append(gTypeHandler.getTokenForEnum(cEnumTypeSystemState,gSystemServices.SystemState.State));
lStream.append('>');*)

