lStream.append('","state":"');
lStream.append(gTypeHandler.getTokenForEnum(cEnumTypeSystemState,gSystemServices.SystemState.State));
lStream.append('",');

IF (lExecuteContext.WriteStream^.Length=0) THEN
	header();
END_IF

lExecuteContext.recordInitiator();
event^.describe(ADR(lExecuteContext));
lExecuteContext.recordTerminatorWithNewline();

IF (lExecuteContext.WriteStream^.Length=0) THEN
	header();
