state^.describe(ADR(lExecuteContext));
lExecuteContext.recordTerminatorWithNewline();

IF (gSystemServices.Cycle.IntegralClockTick) THEN
	lVolumeMbs := UDINT_TO_REAL(lVolumeBits)/1000000.0;
	lVolumeBits := 0;
