	lHandlers[i].ExecuteContext^.ReportError := ReportError;
END_FOR

lReadWrite := ReadWrite;

FOR i:=1 TO cConnectionsLimit DO
	lHandlers[i].ReadWrite := TRUE;
END_FOR

FOR i:=1 TO cConnectionsLimit DO
	lHandlers[i].Interactive := Interactive;
END_FOR

lCloseResult := SysSockClose(hSocket := lClientHandle);

IF (lCloseResult=CmpErrors.Errors.ERR_OK) THEN   
	lState := cSocketStateCreate;
END_IF

lClientHandle := SysTypes.RTS_INVALID_HANDLE;
lState := cSocketStateCreate; //foobar

CASE lState OF
	cSocketStateCreate:
		create();

	cSocketStateIOCtl:
		ioctl();

	cSocketStateBind:
		bind();

	cSocketStateConnect:
		connect();

	cSocketStateConnected:
		connected();

	cSocketStateClose:
		close();
END_CASE

lIOCtlResult := SysSockIoctl(hSocket := lClientHandle,
	diCommand := SOCKET_FIONBIO,
	pdiParameter := ADR(lSysSockIoCtl_Param));

IF (lIOCtlResult=CmpErrors.Errors.ERR_OK) THEN   
	lState := cSocketStateConnect;
END_IF

lVRServerPort.initializeValueReference(lServerPort,NopSelf,'Port','Default port','',cValueStyleParameter);

lState := cSocketStateCreate;
lCloseCount := 0;
lAttempts := 0;

lClientHandle := SysTypes.RTS_INVALID_HANDLE;

SUPER^.initialize();

IF (lState<>cSocketStateConnected) THEN
	operator();
	IF (lState<>cSocketStateConnected) THEN
		RETURN;
	END_IF
END_IF

IF (length=0) THEN
	RETURN;
END_IF

lWritten := lWritten + length;

lSendReturnValue := TO_DINT(SysSockSend(hSocket := lClientHandle,
	pbyBuffer := buffer,
	diBufferSize := length,  
	diFlags := 0,
	pResult := ADR(lSendResult)));

IF ((lSendReturnValue<>length) OR
	(lSendResult<>CmpErrors.Errors.ERR_OK)) THEN   
	lState := cSocketStateClose;
	lCloseCount := lCloseCount + 1;
END_IF

      // Create a connection from this client to a TCP server
lSocketAddress.sin_family := SOCKET_AF_INET;
lSocketAddress.sin_port := SysSockHtons(usHost := lServerPort);

lSocketAddress.sin_addr.S_un_b.s_b1 := 10;
lSocketAddress.sin_addr.S_un_b.s_b2 := 2; 
lSocketAddress.sin_addr.S_un_b.s_b3 := 3; 
lSocketAddress.sin_addr.S_un_b.s_b4 := 10;

lConnectResult := SysSockConnect(hSocket := lClientHandle,
	pSockAddr := ADR(lSocketAddress),
	diSockAddrSize := SIZEOF(lSocketAddress)); 

IF (lConnectResult=CmpErrors.Errors.ERR_OK) THEN   
	lState := cSocketStateConnected;
END_IF

IF (lState<>cSocketStateConnected) THEN
	RETURN;
END_IF

IF (length=0) THEN
	RETURN;
END_IF

IF (lSuppressWrite) THEN
	RETURN;
END_IF

lSendReturnValue := TO_DINT(SysSockSend(hSocket := lClientHandle,
	pbyBuffer := buffer,
	diBufferSize := length,  
	diFlags := 0,
	pResult := ADR(lSendResult)));

IF (lSendResult=CmpErrors.Errors.ERR_OK) THEN
	lWriteCount := lWriteCount + 1;
	RETURN;
END_IF

IF (lSendResult=CmpErrors.Errors.ERR_SOCK_CLOSED) THEN
	lState := cSocketStateClose;

	RETURN;
END_IF

IF ((lSendReturnValue<>length) OR
	(lSendResult=CmpErrors.Errors.ERR_SOCK_WOULDBLOCK)) THEN  
	lOverflowError := lOverflowError + 1;
	lState := cSocketStateClose;

	RETURN;
END_IF

lWriteError := lWriteError + 1;
lState := cSocketStateClose;

lCloseResult := SysSockClose(hSocket := lClientHandle);

lClientHandle := SysTypes.RTS_INVALID_HANDLE;
lState := cSocketStateInvalid;

lState := cSocketStateInvalid;
lConnectionCount := 0;

lServerHandle := SysTypes.RTS_INVALID_HANDLE;
lClientHandle := SysTypes.RTS_INVALID_HANDLE;

CASE lState OF
	cSocketStateInvalid:
		invalid();

	cSocketStateConnect:
		connect();

	cSocketStateIOCtl:
		ioctl();

	cSocketStateConnected:
		connected();

	cSocketStateClose:
		close();
END_CASE

IF (NOT(fIsValidTCPHandle(lServerHandle))) THEN
	lState := cSocketStateInvalid;
	RETURN;
END_IF

lClientHandle := SysSockAccept(hSocket := lServerHandle,
	pSockAddr := ADR(lSocketAddress), 
	pdiSockAddrSize := ADR(lSocketAddressSize),
	pResult := ADR(lAcceptResult));

IF (fIsValidTCPHandle(lClientHandle)) THEN
	lState := cSocketStateIOCtl;
	lConnectionCount := lConnectionCount + 1;
END_IF

IF (lState<>cSocketStateConnected) THEN
	read := FALSE;
	RETURN;
END_IF

IF (stream=0) THEN
	read := FALSE;
	RETURN;
END_IF

IF (SuppressRead) THEN
	read := FALSE;
	RETURN;
END_IF

IF (NOT(fIsValidTCPHandle(lClientHandle))) THEN
	read := FALSE;
	RETURN;
END_IF

lRecvReturnValue := TO_DINT(SysSockRecv(hSocket := lClientHandle,
	pbyBuffer := stream^.Buffer,
	diBufferSize := stream^.cBufferUseableSize,
	diFlags := 0,
	pResult := ADR(lRecvResult)));

IF (lRecvReturnValue>0) THEN
	stream^.Length := TO_UINT(lRecvReturnValue);
	lReadCount := lReadCount + 1;

	IF (lSkipInitialMessages>0) THEN
		lSkipInitialMessages := lSkipInitialMessages - 1;
		read := FALSE;
		RETURN;
	END_IF

	IF (lEnableSkipCompletingNewline) THEN
		buffer := stream^.Buffer;

		read := NOT((lSkipCompletingNewline) AND
			(lRecvReturnValue=2) AND 
			(buffer[0]=13) AND
			(buffer[1]=10));

		lSkipCompletingNewline := (lRecvReturnValue>2);
	ELSE
		read := TRUE;
	END_IF	

	RETURN;
END_IF

IF ((lRecvResult=CmpErrors.Errors.ERR_OK) OR
	(lRecvResult=CmpErrors.Errors.ERR_SOCK_WOULDBLOCK)) THEN
	read := FALSE;
	RETURN;
END_IF

IF (lRecvResult=CmpErrors.Errors.ERR_SOCK_CLOSED) THEN
	lState := cSocketStateClose;

	read := FALSE;
	RETURN;
END_IF

lReadError := lReadError + 1;
lState := cSocketStateClose;
read := FALSE;

lIOCtlResult := SysSockIoctl(hSocket := lClientHandle,
	diCommand := SOCKET_FIONBIO,
	pdiParameter := ADR(lSysSockIoCtl_Param));

IF (lIOCtlResult=CmpErrors.Errors.ERR_OK) THEN   	
	lSkipCompletingNewline := FALSE;
	lState := cSocketStateConnected;

	IF (lHandler<>0) THEN
		lHandler^.connecting();
		RETURN;
	END_IF
END_IF

lHandler := Handler;

IF (lHandler<>0) THEN
	lHandler^.Connection := THIS;
END_IF

lServerHandle := SysSockCreate(iAddressFamily := SOCKET_AF_INET,
	diType := SOCKET_STREAM,
	diProtocol := SOCKET_IPPROTO_TCP, 
	pResult := ADR(lCreateResult));

IF ((fIsValidTCPHandle(lServerHandle)) AND
	(lCreateResult=CmpErrors.Errors.ERR_OK)) THEN
	lState := cSocketStateIOCtl;

	lConnectionCount := lConnectionCount + 1;
END_IF

lVRServerPortLower.initializeValueReference(lServerPortLower,NopSelf,'PortLower','Lower end of port range','',cValueStyleParameter);
lVRServerPortUpper.initializeValueReference(lServerPortUpper,NopSelf,'PortUpper','Upper end of port range','',cValueStyleParameter);
lVRServerPort.initializeValueReference(lServerPort,NopSelf,'Port','Default port','',cValueStyleParameter);

lState := cSocketStateCreate;
lConnectionCount := 0;

lCurrentServerPort := lServerPort;
lAttempts := 0;

lServerHandle := SysTypes.RTS_INVALID_HANDLE;

SUPER^.initialize();

IF (lState<>cSocketStateConnect) THEN
	RETURN;
END_IF

IF (length=0) THEN
	RETURN;
END_IF

IF (lSuppressWrite) THEN
	RETURN;
END_IF

FOR i:=1 TO cConnectionsLimit DO
	lConnections[i].write(buffer,length);
END_FOR

lCloseResult := SysSockClose(hSocket := lServerHandle);

lCurrentServerPort := lServerPort;
lAttempts := 0;

lServerHandle := SysTypes.RTS_INVALID_HANDLE;
lState := cSocketStateCreate;

FOR i:=1 TO cConnectionsLimit DO
	lConnections[i].close();
	lConnections[i].ServerHandle := lServerHandle;
END_FOR

lIOCtlResult := SysSockIoctl(hSocket := lServerHandle,
	diCommand := SOCKET_FIONBIO,
	pdiParameter := ADR(lSysSockIoCtl_Param));

IF (lIOCtlResult=CmpErrors.Errors.ERR_OK) THEN   
	lState := cSocketStateBind;
END_IF

IF (NOT(lEnabled)) THEN
	RETURN;
END_IF

CASE lState OF
	cSocketStateCreate:
		create();

	cSocketStateIOCtl:
		ioctl();

	cSocketStateBind:
		bind();

	cSocketStateListen:
		listen();

	cSocketStateConnect:
		connect();

	cSocketStateClose:
		close();
END_CASE

lClientConnected := FALSE;
FOR i:=1 TO cConnectionsLimit DO
	lConnections[i].operator();
	IF (lConnections[i].ClientConnected) THEN
		lClientConnected := TRUE;
	END_IF
END_FOR

IF ((lCurrentServerPort<lServerPortLower) OR
	(lCurrentServerPort>lServerPortUpper)) THEN
	lCurrentServerPort := lServerPortLower;
END_IF

lSocketAddress.sin_family := SOCKET_AF_INET;
lSocketAddress.sin_port := SysSockHtons(usHost := lCurrentServerPort);    
lSocketAddress.sin_addr.ulAddr := SOCKET_INADDR_ANY;

lBindResult := SysSockBind(hSocket := lServerHandle,
	pSockAddr := ADR(lSocketAddress),
	diSockAddrSize := SIZEOF(lSocketAddress));

IF (lBindResult=CmpErrors.Errors.ERR_OK) THEN 
	lState := cSocketStateListen;
ELSE
	lAttempts := lAttempts + 1;

	IF (lAttempts>=lAttemptsLimit) THEN
		lAttempts := 0;

		lCurrentServerPort := lCurrentServerPort + 1;
		IF (lCurrentServerPort>lServerPortUpper) THEN
			lCurrentServerPort := lServerPortLower;
		END_IF
	END_IF
END_IF

lListenResult := SysSockListen(hSocket := lServerHandle,
	diMaxConnections := cConnectionsLimit); 

IF (lListenResult=CmpErrors.Errors.ERR_OK) THEN   
	lState := cSocketStateConnect;

	FOR i:=1 TO cConnectionsLimit DO
		lConnections[i].ServerHandle := lServerHandle;
	END_FOR
//ELSE
	//lState := cSocketStateClose;
END_IF

IF (executeContext^.matchCommand(sCommandClose)) THEN	
	close();
	RETURN;
END_IF

