lDiagnostic := _Diagnostic;
_Diagnostic := cUInterfaceDiagnosticOK;

SUPER^.operator();

(* events for radios that are not present are ignored if in multi mode *)
IF (lSingleMode) THEN
	lUIMode := cUIModeSingle;
END_IF

IF ((NOT(Estop)) AND (lUIMode>cUIModeInoperable)) THEN
	Diagnostic := cUInterfaceDiagnosticEstop;

	lAlarmUInterfaceEstop.trigger(FALSE);
END_IF

IF ((NOT(Stop)) AND (lUIMode>cUIModeInoperable)) THEN
	Diagnostic := cUInterfaceDiagnosticStop;

	lAlarmUInterfaceStop.trigger(FALSE);
END_IF

IF ((NOT(Emgy)) AND (lUIMode>cUIModeInoperable))  THEN
	Diagnostic := cUInterfaceDiagnosticEmgy;

	lAlarmUInterfaceEmgy.trigger(FALSE);
END_IF

lReady := ((Stop) AND (Emgy) AND (Estop));
IF (NOT(Ready)) THEN
	lUIMode := cUIModeInoperable;

	IF (lSingleMode) THEN
		Diagnostic := cUInterfaceDiagnosticNotReady;

		lAlarmUInterfaceNotReady.trigger(FALSE);
	END_IF
END_IF

