mByteA := fInsertBool(pData:=mBoolA,pStart:=mStartA);
mByteB := fInsertBits(pData:=mIntA,pStart:=mStartB);
mByteC := fMergeBits(pByte:=mByteA,pData:=mIntB,pStart:=mStartC);

mWordA := fInsertBoolIntoWord(pData:=mBoolA,pStart:=mStartD);
mWordB := fInsertBitsIntoWord(pData:=mIntA,pStart:=mStartE);
mWordC := fMergeBitsIntoWord(pWord:=mWordA,pData:=mIntB,pStart:=mStartF);

mBoolB := fExtractBool(pByte:=mByteA,pStart:=mStartA);
mBoolC := fExtractBoolFromWord(pWord:=mWordA,pStart:=mStartD);

mIntC := fExtractBits(pByte:=mByteB,pStart:=mStartB,pLength:=mLengthA);
mIntD := fExtractBitsFromWord(pWord:=mWordB,pStart:=mStartE,pLength:=mLengthB);

mWordD :=  fExtractWord(pByte1:=mByteA ,pByte2:=mByteB);

SUPER^.operator();

lFalling := ((NOT(Value)) AND (lPreviousValue));
lRising := ((Value) AND (NOT(lPreviousValue)));

lPreviousValue := Value;

IF (NOT(__ISVALIDREF(lCheckReference))) THEN
	lCheckReference REF= _CheckReference;
END_IF

_CheckReference := 0;

SUPER^.initialize();

lTimer.initialize();
lTimer.Enable := true;

lValue := lPrevious := lError := lOK := lOKOff := lOff := lChanged := FALSE;

IF (lPrevious<>lValue) THEN
	lChanged := TRUE;
	lPrevious := lValue;
	lTimer.reset();
ELSE
	lChanged := FALSE;
END_IF

SUPER^.operator();

lTimer.operator();

lError := ((lTimer.lExpired) AND
	(lValue) AND
	(lCheckEnable) AND
	(DINT_TO_BOOL(lCheckReference)<>lCheckRequiredValue));	

(* waits to set OK until timer has expired *)
lOK :=  ((lTimer.lExpired) AND (lValue) AND (NOT(lError)));
lOKOff :=  ((lTimer.lExpired) AND (NOT(lValue)) AND (NOT(lError)));
lOff := ((lTimer.lExpired) AND (NOT(lValue)));

IF (NOT(__ISVALIDREF(lOutputReference))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

SUPER^.initialize();

IF (lBelowIsOn) THEN
	// generally lThresholdBelowIsOn (off->on) < lThresholdLowerOff (on->off)
	IF ((lInput<=lThresholdOn) OR
		((lValue) AND (lInput<=lThresholdOff))) THEN
		lValue := TRUE;
	ELSE
		lValue := FALSE;
	END_IF
ELSE
	// generally lThresholdUpperOn (off->on) > lThresholdUpperOff (on->off)
	IF ((lInput>=lThresholdOn) OR
		((lValue) AND (lInput>=lThresholdOff))) THEN
		lValue := TRUE;
	ELSE
		lValue := FALSE;
	END_IF
END_IF

SUPER^.operator();

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	executeContext^.describeSyntaxConfigurable(lStyle,cTokenThreshold,cDataTypeReal,cEnumTypeNone,lUnits,cDescriptionThreshold);
	executeContext^.describeSyntaxConfigurable(lStyle,cTokenHysteresis,cDataTypeReal,cEnumTypeNone,lUnits,cDescriptionHysteresis);

	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN
	executeContext^.describeParameter(lStyle,lIdentity,cTokenThreshold,gTypeHandler.getTokenForReal(lThreshold),cDataTypeReal,cEnumTypeNone,lUnits,cDescriptionThreshold);
	executeContext^.describeParameter(cValueStyleParameter,lIdentity,cTokenHysteresis,gTypeHandler.getTokenForReal(lHysteresis),cDataTypeReal,cEnumTypeNone,lUnits,cDescriptionHysteresis);

	RETURN;
END_IF

executeContext^.appendTokenPair(cTokenThreshold,gTypeHandler.getTokenForReal(lThreshold),FALSE,TRUE);
executeContext^.appendTokenPair(cTokenHysteresis,gTypeHandler.getTokenForReal(lHysteresis),FALSE,TRUE);
executeContext^.appendTokenPair(cTokenHysteresis,gTypeHandler.getTokenForUSINT(BOOL_TO_USINT(lBelowIsOn)),FALSE,TRUE);

IF (executeContext^.configureReal(cTokenThreshold,lThreshold,FALSE,THIS)) THEN
	RETURN;
END_IF

IF (executeContext^.configureReal(cTokenHysteresis,lHysteresis,FALSE,THIS)) THEN
	RETURN;
END_IF

