	lThresholdOff := Threshold + lHysteresis;
	lThresholdOn := Threshold - lHysteresis;
ELSE
	lThresholdOff := Threshold - lHysteresis;
	lThresholdOn := Threshold + lHysteresis;	
END_IF

IF (lHysteresis=Hysteresis) THEN
	RETURN;
END_IF

lHysteresis := Hysteresis;
setThresholds();

IF (lThreshold=Threshold) THEN
