lExpiredEvent := FALSE;

// trigger on falling, automatically a one off event
IF (lTriggerOnFalling) THEN
	IF ((lExpired) AND (lFalling)) THEN
		lExpiredEvent := TRUE;
	END_IF

// otherwise require check to ensure one off event
ELSE
	IF ((lExpired) AND (NOT(lExpiredTriggered))) THEN
		lExpiredEvent := lExpiredTriggered := TRUE;
	END_IF
END_IF

// reset one off check
IF (NOT(lInput)) THEN
	lExpiredTriggered  := FALSE;
END_IF

// short event that did not last long enough
lFastEvent := FALSE;
IF ((lFalling) AND (NOT(lExpired))) THEN
	lFastEvent := TRUE;
END_IF

lPreviousInput := lInput;
lValue := lExpiredEvent;

