Name := _name;
Description := description;
lUnits := units;
lStyle := style;

IF (p=0) THEN
	gCodeErrorHandler(pMessage:='initializing value with null t_particle_op');
	RETURN;
END_IF

p^.registerOperational(THIS);

configureDWORD := matchArgument(parameter,valueToken);

IF (NOT(configureDWORD)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getDWORDFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

recordInitiator();

appendTokenPair(parameter,gTypeHandler.getTokenForDataType(dataType),TRUE,FALSE);

append(', "_metadata":');
recordInitiator();

appendPair('style',gTypeHandler.getTokenForEnum(cEnumTypeValueStyle,style),TRUE,FALSE);
appendPair('units',units,TRUE,TRUE);
appendPair('description',description,TRUE,TRUE);

IF (enumType<>cEnumTypeNone) THEN
	appendPair('enum',gTypeHandler.getStringForEnumOptions(enumType),FALSE,TRUE);
END_IF

recordTerminator();
recordTerminatorWithNewline();

configureUSINT := matchArgument(parameter,valueToken);

IF (NOT(configureUSINT)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getUSINTFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

configureUINT := matchArgument(parameter,valueToken);

IF (NOT(configureUINT)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getUINTFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

configureMediumString := matchArgument(parameter,valueToken);

IF (NOT(configureMediumString)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

target := valueToken;

gSystemServices.Executor.reportParameterUpdates(particle);

configureUDINT := matchArgument(parameter,valueToken);

IF (NOT(configureUDINT)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getUDINTFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

configureReal := matchArgument(parameter,valueToken);

IF (NOT(configureReal)) THEN
