		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getPercentageFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

configureEnum := matchArgument(parameter,valueToken);

IF (NOT(configureEnum)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getEnumFromToken(enumType,valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

configureULINT := matchArgument(parameter,valueToken);

IF (NOT(configureULINT)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getULINTFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

lPassCount := 0;
lWriteStream.clear();

IF (lSkipIndex<lSkipCount) THEN
	lSkipIndex := lSkipIndex + 1;
	RETURN;
END_IF
lSkipIndex := 0;

WHILE (NOT(PassComplete)) DO
	IF (ExecutionComplete) THEN

		IF (lResponsePending) THEN
			lResponsePending := FALSE;

			IF (lWrappedResponse) THEN
				append('], '); 
				lCommaPending := FALSE;

				appendPair('return',gTypeHandler.getTokenForEnum(cEnumTypeExecuteReturn,lExecuteReturn),TRUE,FALSE);	
				lWriteStream.recordTerminatorWithNewline();
				RETURN;
			END_IF

			IF ((lReportError) AND
				(NOT(lExecuteReturn=cExecuteReturnOK))) THEN
				append(gTypeHandler.getTokenForEnum(cEnumTypeExecuteReturn,lExecuteReturn));
				lWriteStream.newline();
			END_IF
		END_IF

		IF (NOT(getNextExecuteCommand())) THEN
			RETURN;
		END_IF

		IF (NOT(lResponsePending)) THEN
			lResponsePending := TRUE;

			IF (lWrappedResponse) THEN
				lCommaPending := FALSE;
				recordInitiator();
				append('"response": [');
			END_IF
		END_IF
	END_IF

	executeNextInQueue();
END_WHILE

IF (particle=0) THEN
	ExecuteReturn := cExecuteReturnExecutionQueueNullParticle;
	lError := TRUE;

	RETURN;
END_IF

particle^.recurse(THIS);

// eolus := getUDINTFromToken(executeContext^.ParameterToken,index,lParseOK);

IF (lExecutionQueueCount>=cExecutionQueueMax) THEN
	executeContextFail(THIS,cExecuteReturnExecutionQueueOverflow,TRUE);
	RETURN;
END_IF

IF (particle=0) THEN
	executeContextFail(THIS,cExecuteReturnExecutionQueueNullParticle,TRUE);
	RETURN;
END_IF

lExecutionQueueCount := lExecutionQueueCount + 1;

lExecutionQueue[lExecutionQueueCount].depth := lRegisterDepth;
lExecutionQueue[lExecutionQueueCount].particle := particle;

IF (ExecutionComplete) THEN
	RETURN;
END_IF

IF (PassComplete) THEN
	RETURN;
END_IF

lExecutionQueueIndex := lExecutionQueueIndex + 1;
lPassCount := lPassCount + 1;

FOR i:=1 TO lCurrentCommand.argumentCount DO
	lCurrentCommand.arguments[i].processed := FALSE;
END_FOR

iterations := 0;
WHILE ((NOT(Error)) AND
	(((lCurrentCommand.command=cTokenConfigure) AND (ArgsUnprocessed)) OR
	(iterations=0))) DO	

	lExecutionQueue[lExecutionQueueIndex].particle^.execute(THIS);

	IF (iterations>lCurrentCommand.argumentCount) THEN
		executeContextFail(THIS,cExecuteReturnInternalError,TRUE);
	END_IF
	iterations := iterations + 1;

END_WHILE

IF (ArgsUnprocessed) THEN
	executeContextFail(THIS,cExecuteReturnUnprocessedArguments,TRUE);
END_IF

IF (matchOption(cExecuteOptionPersist)) THEN
	IF (NOT(gSystemServices.PLC.persistCommand(lCurrentCommand))) THEN
		executeContextFail(THIS,cExecuteReturnPersistFailed,TRUE);
	END_IF
END_IF

recordInitiator();

appendPair('command',gTypeHandler.getTokenForEnum(cEnumTypeTokenType,command.command),TRUE,FALSE);

append(', "_metadata":');
recordInitiator();

options := '[';

FOR i:=1 TO command.optionCount DO
	IF (i=1) THEN
		options := CONCAT(options,'"');
	ELSE
		options := CONCAT(options,', "');
	END_IF

	options := CONCAT(options,gTypeHandler.getTokenForEnum(cEnumTypeExecuteOption,command.options[i]));
	options := CONCAT(options,'"');
END_FOR

options := CONCAT(options,']');

appendPair('options',options,TRUE,FALSE);
IF (__ISVALIDREF(command.description)) THEN
	appendPair('description',command.description,TRUE,TRUE);
END_IF

recordTerminator();
recordTerminatorWithNewline();

IF ((lWrappedResponse) AND (lCommaPending)) THEN
	lWriteStream.append(', ');
	lCommaPending := FALSE;
END_IF

lWriteStream.recordInitiator();

IF (lWrappedResponse) THEN
	lWriteStream.recordTerminator();
	lCommaPending := TRUE;

	RETURN;
END_IF

lWriteStream.recordTerminatorWithNewline();

IF (style<>cValueStyleParameter) THEN
	RETURN;
END_IF

CASE dataType OF	
	cDataTypeNone:
		RETURN;

	cDataTypeEnum,
	cDataTypeString:
		quoted := TRUE;

	cDataTypeUSINT,
	cDataTypeUINT,
	cDataTypeULINT,
	cDataTypeUDINT,
	cDataTypeINT,
	cDataTypePercentage,
	cDataTypeReal,
	cDataTypeDWORD,
	cDataTypeBool:
		quoted := FALSE;
END_CASE

recordInitiator();

id := identity;
IF (parameter<>cTokenNone) THEN
	id := CONCAT(id,'/');
	id := CONCAT(id,gTypeHandler.getTokenForEnum(cEnumTypeTokenType,parameter));
END_IF

appendPair('identity',id,TRUE,FALSE);
appendPair('value',value,quoted,TRUE);

IF (NOT(matchOption(cExecuteOptionMetadata))) THEN
	recordTerminatorWithNewline();
	RETURN;
END_IF

append(', "_metadata":');
recordInitiator();

IF (enumType=cEnumTypeNone) THEN
	appendPair('type',gTypeHandler.getTokenForDataType(dataType),TRUE,FALSE);
ELSE
	appendPair('type',gTypeHandler.getTokenForEnumType(enumType),TRUE,FALSE);	
	appendPair('enum',gTypeHandler.getStringForEnumOptions(enumType),FALSE,TRUE);
END_IF

appendPair('units',units,TRUE,TRUE);
appendPair('description',description,TRUE,TRUE);

recordTerminator();
recordTerminatorWithNewline();

configureBool := matchArgument(parameter,valueToken);

IF (NOT(configureBool)) THEN
	IF (required) THEN
		executeContextFail(THIS,cExecuteReturnMissingArgument,TRUE);		
	END_IF

	RETURN;
END_IF

IF (NOT(gTypeHandler.getBoolFromToken(valueToken,target))) THEN
	executeContextFail(THIS,cExecuteReturnParseParameterError,TRUE);
	RETURN;
END_IF

gSystemServices.Executor.reportParameterUpdates(particle);

lError := FALSE;
lExecuteReturn := cExecuteReturnOK;

lExecutionQueueCount := 0;
lExecutionQueueIndex := 0;
lRegisterDepth := 0;

IF (NOT(_getNextExecuteCommand())) THEN
	getNextExecuteCommand := FALSE;
	RETURN;
END_IF

getNextExecuteCommand := TRUE;

IF (lCurrentCommand.command=cTokenNone) THEN
	executeContextFail(THIS,cExecuteReturnExecutionQueueNullParticle,TRUE);		
	RETURN;	
END_IF

IF (lCurrentCommand.particle=0) THEN
	executeContextFail(THIS,cExecuteReturnExecutionQueueNullParticle,TRUE);		
	RETURN;
END_IF

IF (lEnableExecutor) THEN
	IF (matchOption(cExecuteOptionExecutor)) THEN	
		IF (NOT(gSystemServices.Executor.putCommand(lCurrentCommand))) THEN
			executeContextFail(THIS,cExecuteReturnExecutionExecutorFailed,TRUE);	
		END_IF

		RETURN;
	END_IF
END_IF

IF ((matchOption(cExecuteOptionRecurse)) OR
	(matchOption(cExecuteOptionSubsystems))) THEN
	lCurrentCommand.particle^.recurse(THIS);
ELSE
	registerParticle(lCurrentCommand.particle);	
END_IF

IF (lCurrentCommand.command<>contender.command) THEN
	matchCommand := FALSE;
	RETURN;
END_IF

FOR i:=1 TO lCurrentCommand.optionCount DO
	FOR j:=1 TO cExecuteOptionListCount DO
		IF (lCurrentCommand.options[i]=contender.options[j]) THEN
			EXIT;
		END_IF
	END_FOR

	IF (j>cExecuteOptionListCount) THEN
		executeContextFail(THIS,cExecuteReturnUnknownOption,TRUE);		
	END_IF
END_FOR

IF (lCurrentCommand.argumentCount<contender.pairMinCount) THEN
	executeContextFail(THIS,cExecuteReturnTooFewArguments,TRUE);		
END_IF

IF (lCurrentCommand.argumentCount>contender.pairMaxCount) THEN
	executeContextFail(THIS,cExecuteReturnTooManyArguments,TRUE);		
END_IF

IF ((contender.readwrite) AND (NOT(lReadWrite))) THEN
	executeContextFail(THIS,cExecuteReturnReadOnly,TRUE);
END_IF

matchCommand := TRUE;

FOR i:=1 TO lCurrentCommand.optionCount DO
	IF (lCurrentCommand.options[i]=option) THEN
		matchOption := TRUE;
		RETURN;
	END_IF
END_FOR

matchOption := FALSE;

FOR i:=1 TO lCurrentCommand.argumentCount DO
	IF ((lCurrentCommand.arguments[i].parameter=parameter) AND
		(NOT(lCurrentCommand.arguments[i].processed))) THEN
		value := lCurrentCommand.arguments[i].value;
		lCurrentCommand.arguments[i].processed := TRUE;

		matchArgument := TRUE;	
		RETURN;
	END_IF
END_FOR

matchArgument := FALSE;

IF (particle=0) THEN
	RETURN;
END_IF

recordInitiator();	
appendPair('identity',particle^.lIdentity,TRUE,FALSE);
appendPair('type',particle^.TypeToken,TRUE,TRUE);
appendPair('subsystem',gTypeHandler.getTokenForEnum(cEnumTypeSubsystem,particle^.SubSystem),TRUE,TRUE);
recordTerminatorWithNewline();

FOR i:=1 TO lCurrentCommand.argumentCount DO
	IF (NOT(lCurrentCommand.arguments[i].processed)) THEN
		ArgsUnprocessed := TRUE;
		RETURN;
	END_IF
END_FOR

ArgsUnprocessed := FALSE;

lWrappedResponse := WrappedResponse;

IF (WrappedResponse) THEN
	lWriteStream.IndentStr := '';
ELSE
	lWriteStream.IndentStr := '    ';	
END_IF

FOR i:=1 TO lNonOperationalParticleCount DO
	IF (id>0) THEN
		particle := lNonOperationalParticleSet[i]^.getParticle(name,id);
		IF (particle<>0) THEN
			getParticle := particle;
			RETURN;
		END_IF
	ELSE
		IF (strcmp(name,lNonOperationalParticleSet[i]^.lName)) THEN
			getParticle := lNonOperationalParticleSet[i];
			RETURN;
		END_IF		
	END_IF
END_FOR

getParticle := SUPER^.getParticle(name,id);

SUPER^.initialize();

FOR i:=1 TO lNonOperationalParticleCount DO
	IF (lNonOperationalParticleSet[i]^.lParticleId=0) THEN
		lNonOperationalParticleSet[i]^.initialize();
	END_IF
END_FOR

IF (particle=0) THEN
	RETURN;
END_IF

IF (lNonOperationalParticleCount>=cNopParticleSetMax) THEN
	gCodeErrorHandler(pMessage:='NonOperationalParticleSet overflow');
	RETURN;
END_IF

lNonOperationalParticleCount := lNonOperationalParticleCount + 1;
lNonOperationalParticleSet[lNonOperationalParticleCount] := particle;
particle^.Parent := THIS;
//particle^.System REF= System;
particle^.SubSystem := SubSystem;

SUPER^.identify();

FOR i:=1 TO lNonOperationalParticleCount DO
	lNonOperationalParticleSet[i]^.identify();
END_FOR

SUPER^.loadExecutionContext(executeContext);

IF (executeContext=0) THEN
	RETURN;
END_IF

IF (lProceed) THEN
	executeContext^.registerDepthIncrease();
	FOR i:=1 TO lNonOperationalParticleCount DO
		lNonOperationalParticleSet[i]^.loadExecutionContext(executeContext);
	END_FOR
	executeContext^.registerDepthDecrease();
END_IF

SUPER^.recurse(executeContext);

IF (NOT(executeContext^.matchOption(cExecuteOptionRecurse))) THEN	
	RETURN;
END_IF

FOR i:=1 TO lNonOperationalParticleCount DO
	lNonOperationalParticleSet[i]^.recurse(executeContext);
END_FOR

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN
	RETURN;
END_IF

IF (NOT(executeContext^.matchOption(cExecuteOptionChildren))) THEN
	RETURN;
END_IF

executeContext^.append(', ');
executeContext^.WriteStream^.increaseIndent();
executeContext^.formatWithNewlineIndent();
executeContext^.append('"nop-children": [');
executeContext^.WriteStream^.increaseIndent();

FOR i:=1 TO lNonOperationalParticleCount DO
	executeContext^.recordInitiatorWithNewlineIndent();
	executeContext^.appendPair('identity',lNonOperationalParticleSet[i]^.lIdentity,TRUE,FALSE);
	executeContext^.appendPair('type',lNonOperationalParticleSet[i]^.TypeToken,TRUE,TRUE);
	executeContext^.appendPair('subsystem',gTypeHandler.getTokenForEnum(cEnumTypeSubsystem,lNonOperationalParticleSet[i]^.SubSystem),TRUE,TRUE);
	executeContext^.recordTerminator();

	IF (i<lNonOperationalParticleCount) THEN
		executeContext^.append(', ');		
	END_IF
END_FOR

executeContext^.WriteStream^.decreaseIndent();
executeContext^.append(']');
executeContext^.WriteStream^.decreaseIndent();

IF (lSubSystem=cSubsystemNone) THEN
	lSubSystem := SubSystem;

	FOR i:=1 TO lNonOperationalParticleCount DO
		lNonOperationalParticleSet[i]^.SubSystem := lSubSystem;
	END_FOR
END_IF

SUPER^.FailSafeMode := FailSafeMode;

IF (lProceed) THEN
	FOR i:=1 TO lNonOperationalParticleCount DO
		lNonOperationalParticleSet[i]^.FailSafeMode := FailSafeMode;
	END_FOR		
END_IF

FOR i:=1 TO lOperationalParticleCount DO
	IF (id>0) THEN
		particle := lOperationalParticleSet[i]^.getParticle(name,id);
		IF (particle<>0) THEN
			getParticle := particle;
			RETURN;
		END_IF
	ELSE
		IF (strcmp(name,lOperationalParticleSet[i]^.lName)) THEN
			getParticle := lOperationalParticleSet[i];
			RETURN;
		END_IF		
	END_IF
END_FOR

getParticle := SUPER^.getParticle(name,id);

SUPER^.initialize();

FOR i:=1 TO lOperationalParticleCount DO
	IF (lOperationalParticleSet[i]^.lParticleId=0) THEN
		lOperationalParticleSet[i]^.initialize();
	END_IF
END_FOR

IF (NOT(lProceed)) THEN
	RETURN;
END_IF

FOR i:=1 TO lOperationalParticleCount DO
	IF (lOperationalParticleSet[i]^.lProceed) THEN
		lOperationalParticleSet[i]^.operator();
	END_IF
END_FOR

SUPER^.operator();

IF (particle=0) THEN
	RETURN;
END_IF

IF (lOperationalParticleCount>=cOpParticleSetMax) THEN
	gCodeErrorHandler(pMessage:='OperationalParticleSet overflow');
	RETURN;
END_IF

lOperationalParticleCount := lOperationalParticleCount + 1;
lOperationalParticleSet[lOperationalParticleCount] := particle;
particle^.Parent := THIS;
//particle^.System REF= System;
particle^.SubSystem := SubSystem;

SUPER^.identify();

FOR i:=1 TO lOperationalParticleCount DO
	lOperationalParticleSet[i]^.identify();
END_FOR

SUPER^.loadExecutionContext(executeContext);

IF (executeContext=0) THEN
	RETURN;
END_IF

IF (lProceed) THEN
	executeContext^.registerDepthIncrease();
	FOR i:=1 TO lOperationalParticleCount DO
		lOperationalParticleSet[i]^.loadExecutionContext(executeContext);
	END_FOR
	executeContext^.registerDepthDecrease();
END_IF

SUPER^.recurse(executeContext);

IF (NOT(executeContext^.matchOption(cExecuteOptionRecurse))) THEN	
	RETURN;
END_IF

FOR i:=1 TO lOperationalParticleCount DO
	lOperationalParticleSet[i]^.recurse(executeContext);
END_FOR

SUPER^.describe(executeContext);

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN
	RETURN;
END_IF

IF (NOT(executeContext^.matchOption(cExecuteOptionChildren))) THEN
	RETURN;
END_IF

executeContext^.append(', ');
executeContext^.WriteStream^.increaseIndent();
executeContext^.formatWithNewlineIndent();
executeContext^.append('"op-children": [');
executeContext^.WriteStream^.increaseIndent();

FOR i:=1 TO lOperationalParticleCount DO
	executeContext^.recordInitiatorWithNewlineIndent();
	executeContext^.appendPair('identity',lOperationalParticleSet[i]^.lIdentity,TRUE,FALSE);
	executeContext^.appendPair('type',lOperationalParticleSet[i]^.TypeToken,TRUE,TRUE);
	executeContext^.appendPair('subsystem',gTypeHandler.getTokenForEnum(cEnumTypeSubsystem,lOperationalParticleSet[i]^.SubSystem),TRUE,TRUE);
	executeContext^.recordTerminator();

	IF (i<lOperationalParticleCount) THEN
		executeContext^.append(', ');		
	END_IF
END_FOR

executeContext^.WriteStream^.decreaseIndent();
executeContext^.append(']');
executeContext^.WriteStream^.decreaseIndent();

ChildrenOK := TRUE;

FOR i:=1 TO lOperationalParticleCount DO
	IF (NOT(lOperationalParticleSet[i]^.OK)) THEN
		ChildrenOK := FALSE;
	END_IF
END_FOR

IF (lSubSystem=cSubsystemNone) THEN
	lSubSystem := SubSystem;

	FOR i:=1 TO lOperationalParticleCount DO
		lOperationalParticleSet[i]^.SubSystem := lSubSystem;
	END_FOR

	FOR i:=1 TO lNonOperationalParticleCount DO
		lNonOperationalParticleSet[i]^.SubSystem := lSubSystem;
	END_FOR
END_IF

SUPER^.FailSafeMode := FailSafeMode;

IF (lProceed) THEN
	FOR i:=1 TO lOperationalParticleCount DO
		lOperationalParticleSet[i]^.FailSafeMode := FailSafeMode;
	END_FOR
END_IF

IF (executeContext^.configureBool(cTokenProceed,lProceed,FALSE,THIS)) THEN
	RETURN;
END_IF

IF (executeContext^.configureBool(cTokenFailSafeConfig,lFailSafeConfig,FALSE,THIS)) THEN
	RETURN;
END_IF

executeContextFail(executeContext,cExecuteReturnUnknownParameter,TRUE);

gParticleDebugIdB := lParticleId;

IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
	executeContext^.describeSyntaxExecutable(sCommandDescribe);
	executeContext^.describeSyntaxExecutable(sCommandVerify);
	executeContext^.describeSyntaxExecutable(sCommandIdentify);
	executeContext^.describeSyntaxExecutable(sCommandSetFailSafeMode);
	executeContext^.describeSyntaxExecutable(sCommandClearFailSafeMode);

	executeContext^.describeSyntaxConfigurable(cValueStyleParameter,cTokenProceed,cDataTypeBool,cEnumTypeNone,'',cDescriptionProceed);
	executeContext^.describeSyntaxConfigurable(cValueStyleParameter,cTokenFailSafeConfig,cDataTypeBool,cEnumTypeNone,'',cDescriptionFailSafeConfig);

	RETURN;
END_IF

IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN
	executeContext^.describeParameter(cValueStyleConfigurable,lIdentity,cTokenProceed,gTypeHandler.getTokenForBool(lProceed),cDataTypeBool,cEnumTypeNone,'',cDescriptionProceed);
	executeContext^.describeParameter(cValueStyleConfigurable,lIdentity,cTokenFailSafeConfig,gTypeHandler.getTokenForBool(lFailSafeConfig),cDataTypeBool,cEnumTypeNone,'',cDescriptionFailSafeConfig);

	RETURN;
END_IF

executeContext^.appendPair('identity',lIdentity,TRUE,FALSE);
executeContext^.appendPair('type',TypeToken,TRUE,TRUE);
executeContext^.appendPair('subsystem',gTypeHandler.getTokenForEnum(cEnumTypeSubsystem,SubSystem),TRUE,TRUE);
executeContext^.appendPair('description',lDescription,TRUE,TRUE);

IF (executeContext^.matchOption(cExecuteOptionVerbose)) THEN
	executeContext^.appendTokenPair(cTokenProceed,gTypeHandler.getTokenForBool(lProceed),FALSE,TRUE);
	executeContext^.appendTokenPair(cTokenFailSafeConfig,gTypeHandler.getTokenForBool(lFailSafeConfig),FALSE,TRUE);
END_IF

IF (executeContext=0) THEN
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandConfigure)) THEN
	configure(executeContext);
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandVerify)) THEN
	verify(executeContext);
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandSetFailSafeMode)) THEN
	FailSafeMode := TRUE;
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandClearFailSafeMode)) THEN
	FailSafeMode := FALSE;
	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandDescribe)) THEN

	IF (executeContext^.matchOption(cExecuteOptionSyntax)) THEN
		executeContext^.recordInitiator();
		executeContext^.appendPair('identity',lIdentity,TRUE,FALSE);
		executeContext^.append(',"syntax": [');
		describe(executeContext);
		executeContext^.append(']');
		executeContext^.recordTerminatorWithNewline();

		RETURN;
	END_IF

	IF (executeContext^.matchOption(cExecuteOptionParameter)) THEN
		describe(executeContext);
		RETURN;
	END_IF

	executeContext^.recordInitiator();
	describe(executeContext);
	executeContext^.recordTerminatorWithNewline();

	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandIdentify)) THEN
	executeContext^.appendIdentity(THIS);
	RETURN;
END_IF

executeContextFail(executeContext,cExecuteReturnUnknownCommand,TRUE);

getParticle := 0;

IF (id>0) THEN
	IF (id=lParticleId) THEN
		getParticle := THIS;
	END_IF

	RETURN;
END_IF

IF (strcmp(name,lName)) THEN
	getParticle := THIS;
	RETURN;
END_IF

IF (strcmp(name,'this')) THEN
	getParticle := THIS;
	RETURN;
END_IF

IF (lParent<>0) THEN
	IF ((find(lIdentity,'/')>0) OR
		(lParent^.lFeature)) THEN
		lIdentity := CONCAT(lParent^.lIdentity,'/');
	ELSE
		lIdentity := CONCAT(lParent^.lIdentity,'.');
	END_IF
	lIdentity := CONCAT(lIdentity,lName);

	RETURN;
END_IF

lIdentity := CONCAT(gNameSpace,'.');
lIdentity := CONCAT(lIdentity,lName);

IF (lParticleId<>0) THEN
	RETURN;
END_IF

Name := TypeToken;

sLastParticleId := sLastParticleId + 1;
lParticleId := sLastParticleId;

IF (lParticleId=0) THEN
	executeContext^.describeVerify(lIdentity,FALSE,'zero ParticleId');
END_IF

IF (strcmp(lName,sDefaultName)) THEN
	executeContext^.describeVerify(lIdentity,FALSE,'default name');
END_IF

IF (strcmp(sParticle,TypeToken)) THEN
	executeContext^.describeVerify(lIdentity,FALSE,'default type');
END_IF

IF (SubSystem=cSubsystemNone) THEN
	executeContext^.describeVerify(lIdentity,FALSE,'default subsystem');
END_IF

//IF (NOT(__ISVALIDREF(_System)))THEN
//	executeContext^.describeVerify(lIdentity,FALSE,'null System reference');
//END_IF

IF ((find(Name,'.')>0) OR
	(find(Name,'/')>0)) THEN
	gCodeErrorHandler(pMessage:='Illegal . or / character in name');
	RETURN;
END_IF

IF (strcmp(lName,sDefaultName)) THEN
	lName := Name;
	identify();
END_IF

IF (FailSafeMode) THEN
	lProceed := lFailSafeConfig;

	gSystemServices.PLC.setFailSafeMode();
ELSE
	lProceed := TRUE;
END_IF

IF ((Value.argumentCount=lValue.argumentCount) AND
	(Value.command=lValue.command) AND
	(Value.optionCount=lValue.optionCount) AND
	(Value.particle=lValue.particle)) THEN

	FOR i:=1 TO lValue.argumentCount DO
		IF (NOT((Value.arguments[i].parameter=lValue.arguments[i].parameter) AND
			(Value.arguments[i].value=lValue.arguments[i].value))) THEN
			equal := FALSE;		
		END_IF
	END_FOR

	FOR i:=1 TO lValue.optionCount DO
		IF (NOT(Value.options[i]=lValue.options[i])) THEN
			equal := FALSE;		
		END_IF
	END_FOR

	IF (equal) THEN
		RETURN;
	END_IF
END_IF

FOR i:=Value.optionCount TO cExecuteOptionListCount DO
	Value.options[i] := 0;
END_FOR

FOR i:=Value.argumentCount TO cExecuteArgumentListCount DO
	Value.arguments[i].parameter := 0;
	Value.arguments[i].value := '';
	Value.arguments[i].processed := FALSE;
END_FOR

lValue := Value;
write();

IF (executeContext=0) THEN
	RETURN;
END_IF

executeContext^.ExecuteReturn := reason;

IF (abort) THEN
	executeContext^.Error := TRUE;
END_IF

IF (writeStream=0) THEN
	RETURN;
END_IF

writeStream^.append(particle^.lIdentity);
writeStream^.append(' skipping <');	
writeStream^.append(parameter);	
writeStream^.append('>=<');	
writeStream^.append(value);	
writeStream^.append('>');
writeStream^.newline();

