SUPER^.execute(executeContext);

IF (lContext=Context) THEN
	RETURN;
END_IF

lContext := Context;
lContextChanged := Active;

IF ((lRegistered) AND (NOT(Registered)) AND (SuppressAfterExpired)) THEN
	Suppress := TRUE;
END_IF

lRegistered := Registered;

IF ((lSuppressUntilExpired) AND (NOT(SuppressUntilExpired))) THEN
	SuppressAfterCountDown := FALSE;
END_IF

lSuppressUntilExpired := SuppressUntilExpired;

IF ((index=0) OR (index>lCurrentCount)) THEN
	RETURN;
END_IF

state := lCurrent[index];

lCurrentCount := lCurrentCount - 1;
FOR i:=index TO lCurrentCount DO
	lCurrent[i] := lCurrent[i+1];
END_FOR
lCurrent[lCurrentCount+1] := 0;

IF (state=0) THEN
	RETURN;
END_IF

state^.Registered := FALSE;
lReportableChannelManager^.reportStateExpired(state);

IF ((lCurrentCount=0) OR 
	(cycleIndex=0)) THEN
	cycle := 0;
	RETURN;
END_IF

IF (cycleIndex^=0) THEN
	cycle := 0;
	RETURN;
END_IF

FOR count:=1 TO lCurrentCount DO
	IF (cycleIndex^>lCurrentCount) THEN
		IF (loop) THEN
			cycleIndex^ := 1;
		ELSE
			cycleIndex^ := 0;
			cycle := 0;
			RETURN;
		END_IF
	END_IF

	state := lCurrent[cycleIndex^]; // foobar assume state is non-null
	cycleIndex^ := cycleIndex^ + 1;

	IF ((NOT(state^.Suppress)) AND
		(NOT(state^.Override)) AND
		(fCheckChannelMask(state^.ChannelMask,mask))) THEN
		cycle := state;
		a := a+ 1;
		RETURN;
	END_IF
END_FOR

b := b+ 1;
cycleIndex^ := 0;
cycle := 0;

