	thresholdPos := ThresholdDischarge;		
END_IF

IF (lNegativeIsCharge) THEN
	scalingNeg := ScalingCharge;
	thresholdNeg:=ThresholdCharge;
ELSE
	scalingNeg := ScalingDischarge;
	thresholdNeg := ThresholdDischarge;	
END_IF

IF ((scalingPos=0.0) OR (thresholdPos=0.0)) THEN
	interlockSt := cInterlockStateErrorPositive;
END_IF
IF ((scalingNeg=0.0) OR (thresholdNeg=0.0)) THEN
	IF (interlockSt=cInterlockStateErrorPositive) THEN
		interlockSt := cInterlockStateError;
	ELSE
		interlockSt := cInterlockStateErrorNegative;		
	END_IF
END_IF

FOR i:=1 TO lServerCount DO
	lServers[i]^.processReportable(THIS,FALSE,
