ThresholdNegative := thresholdNeg;

IF (reportable=0) THEN
	RETURN;
END_IF

IF (reportable^.InterlockState=cInterlockStateNone) THEN
	RETURN;
END_IF

lPendingContext.push(reportable);

IF ((override) OR
	(reportable^.Override)) THEN
	IncludesOverrides := true;
	RETURN;
END_IF

lProcessSignedModulationCount := lProcessSignedModulationCount + 1;

InterlockState := reportable^.InterlockState;
ScalingPositive := reportable^.ScalingPositive;
ScalingNegative := reportable^.ScalingNegative;
ThresholdPositive := reportable^.ThresholdPositive;
ThresholdNegative := reportable^.ThresholdNegative;

IF (Override) THEN
	update := value;
	RETURN;
END_IF

IF (lContext.Count=0) THEN
	update := value;
	RETURN;	
END_IF

IF ((InterlockState>=cInterlockStateOveride) OR
	(InterlockState=cInterlockStateNone) OR
	(InterlockState=cInterlockStateGood)) THEN
	update := value;
	RETURN;
END_IF

IF (InterlockState<=cInterlockStateError) THEN
	update := stop(value);
	RETURN;
END_IF

IF (value<0) THEN
	update := MAX(value*ScalingNegative,-1.0*ABS(ThresholdNegative));
ELSIF (value>0) THEN
	update := MIN(value*ScalingPositive,ABS(ThresholdPositive));
ELSE
	update := value;
END_IF

lInterlockState := cInterlockStateGood;
lScalingPositive := 1.0;
lScalingNegative := 1.0;
lThresholdPositive := 1.0;
lThresholdNegative := 1.0;

