IF (executeContext^.matchCommand(sCommandRegister)) THEN
	IF (NOT(executeContext^.configureUINT(cTokenObject,id,TRUE,THIS))) THEN
		RETURN;
	END_IF

	particle := gSystemServices.getParticle(token,id);
	IF (particle=0) THEN
		executeContextFail(executeContext,cExecuteReturnUnknownArgumentValue,TRUE);
		RETURN;		
	END_IF

	IF (findParticle(particle)>0) THEN
		RETURN;
	END_IF

	IF (lReportableParticleCount>=cReportableParticleSetMax) THEN
		executeContextFail(executeContext,cExecuteReturnSetOverflow,TRUE);
		RETURN;
	END_IF

	lReportableParticleCount := lReportableParticleCount + 1;
	lReportableParticleSet[lReportableParticleCount] := particle;

	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandClear)) THEN

	FOR i:=1 TO lReportableParticleCount DO
		lReportableParticleSet[i] := 0;
	END_FOR
	lReportableParticleCount := 0;

	RETURN;
END_IF

IF (executeContext^.matchCommand(sCommandDeregister)) THEN
	IF (NOT(executeContext^.configureUINT(cTokenObject,id,TRUE,THIS))) THEN
		RETURN;
	END_IF

	particle := gSystemServices.getParticle(token,id);
	IF (particle=0) THEN
		executeContextFail(executeContext,cExecuteReturnUnknownArgumentValue,TRUE);
		RETURN;		
	END_IF

	index := findParticle(particle);
	IF (index=0) THEN
		RETURN;
	END_IF

	lReportableParticleCount := lReportableParticleCount - 1;	
	FOR i:=index TO lReportableParticleCount DO
		lReportableParticleSet[i] := lReportableParticleSet[i+1];
	END_FOR
	lReportableParticleSet[lReportableParticleCount+1] := 0;

	RETURN;
END_IF

