	duration := systemTimeMicroseconds - lRaisedSystemTimeMicroseconds;
ELSE
	duration := 0;
END_IF

CASE Severity OF
	cSeverityNone:
		IF (duration>lSeverityWarningThreshold) THEN
			Severity := cSeverityWarning;
		END_IF

	cSeverityWarning:
		IF (duration>lSeverityErrorThreshold) THEN
			Severity := cSeverityError;
		END_IF

	cSeverityError:
		IF (duration>lSeverityCriticalThreshold) THEN
			Severity := cSeverityCritical;
		END_IF
END_CASE

