SUPER^.initialize();

lValue.setLength();

IF (lValue.Length=0) THEN
	RETURN;
END_IF

lValue.clear();
write();

IF (NOT(__ISVALIDREF(stream))) THEN
	RETURN;	
END_IF

lValue.import(stream);
write();

lng := INT_TO_UINT(len(str));
IF (lng=0) THEN
	RETURN;
END_IF

IF (cBufferUseableSize<=lCharacters) THEN
	lOverflow := TRUE;
	RETURN;
END_IF

avail := cBufferUseableSize - lCharacters;

IF (lng>avail) THEN
	lng := avail;
	lOverflow := TRUE;
END_IF

MEMUtils.MemCpy(ADR(lBuffer[lCharacters]),ADR(str[0]),lng+1);

lCharacters := lCharacters + lng;
lLength := lCharacters + 1;

IF (str=0) THEN
	RETURN;
END_IF

lng := INT_TO_UINT(len(str^));
IF (lng=0) THEN
	RETURN;
END_IF

IF (cBufferUseableSize<=lCharacters) THEN
	lOverflow := TRUE;
	RETURN;
END_IF

avail := cBufferUseableSize - lCharacters;

IF (lng>avail) THEN
	lng := avail;
	lOverflow := TRUE;
END_IF

MEMUtils.MemCpy(ADR(lBuffer[lCharacters]),ADR(str^[0]),lng+1);

lCharacters := lCharacters + lng;
lLength := lCharacters + 1;

IF (lLength=0) THEN
	lCharacters := 0;
	lBuffer[0] := 0;
	lTerminatorPtr := ADR(lBuffer[0]);

	RETURN;
END_IF

IF (lBuffer[lLength-1]<>0) THEN
	lBuffer[lLength] := 0;
	lCharacters := lLength;
	lLength := lLength + 1;
ELSE
	lCharacters := lLength - 1;
END_IF

lTerminatorPtr := ADR(lBuffer[lCharacters]);

lLength := 0;
lCharacters := 0;
lBuffer[0] := 0;
lOverflow := FALSE;
lIndent := '';
lParsePtr := ADR(lBuffer[0]);
lTerminatorPtr := ADR(lBuffer[0]);

lCurrentToken := cParseTokenSimple;

IF (str=0) THEN
	RETURN;
END_IF

lng := MIN(lCharacters,63);
lng := lng + 1;

FOR i:=0 TO lng DO
	str^[i] := lBuffer[i];
END_FOR

l := LEN(lIndent);
i := LEN(lIndentStr);

IF (l<=i) THEN
	lIndent := '';
	RETURN;
END_IF

l := MAX(l-i,i);

lIndent := LEFT(lIndent,l);

lParsePtr := ADR(lBuffer[0]);
lTerminatorPtr := lParsePtr + lLength;
lCurrentToken := cParseTokenSimple;

bytePtr := ADR(tokenPtr^[0]);

IF ((lCurrentToken=cParseTokenError) OR
	(lCurrentToken=cParseTokenOverflow) OR
	(lCurrentToken=cParseTokenFinished)) THEN

	lCurrentToken := cParseTokenFinished;	

	bytePtr^ := 0;
	getNextToken := lCurrentToken;
	parseDebug(getNextToken,tokenPtr);	

	RETURN;	
END_IF

lCurrentToken := cParseTokenSimple;

WHILE (lParsePtr<=lTerminatorPtr) DO
	c := lParsePtr^;

	CASE c OF
		0: // terminator
			IF (length=0) THEN
				lCurrentToken := cParseTokenFinished;
			END_IF

			bytePtr^ := 0;
			getNextToken := lCurrentToken;
			parseDebug(getNextToken,tokenPtr);	
			RETURN;

		32, // space
		9, // tab
		10, // lf
		11, // vtab
		12, // ff
		13: // cr
			lParsePtr := lParsePtr + 1;
			skipWhiteSpace();

			IF (length>0) THEN
				bytePtr^ := 0;
				getNextToken := lCurrentToken;			
				parseDebug(getNextToken,tokenPtr);		
				RETURN;
			END_IF

			CONTINUE;

		35: // #
			lParsePtr := lParsePtr + 1;
			skipPastEOL();

			IF (length>0) THEN		
				bytePtr^ := 0;
				getNextToken := lCurrentToken;			
				parseDebug(getNextToken,tokenPtr);		
				RETURN;
			END_IF

			CONTINUE;

		44, // ,
		59: // ;

			IF (length>0) THEN				
				bytePtr^ := 0;
				getNextToken := lCurrentToken;			
				parseDebug(getNextToken,tokenPtr);		
				RETURN;
			END_IF

			lParsePtr := lParsePtr + 1;
			lCurrentToken := cParseTokenTerminator;

			bytePtr^ := 0;			
			getNextToken := lCurrentToken;			
			parseDebug(getNextToken,tokenPtr);	
			RETURN;			

		47: // /
			IF (NOT(lCurrentToken=cParseTokenSimple)) THEN
				lCurrentToken := cParseTokenError;
			ELSIF (length>0) THEN
				lCurrentToken := cParseTokenName;
			ELSE
				lCurrentToken := cParseTokenError;
			END_IF

			lParsePtr := lParsePtr + 1;	

			bytePtr^ := 0;
			getNextToken := lCurrentToken;			
			parseDebug(getNextToken,tokenPtr);		
			RETURN;

		61: // =
			IF (lCurrentToken=cParseTokenOption) THEN
				lCurrentToken := cParseTokenError;
			ELSIF (length>0) THEN
				lCurrentToken := cParseTokenParameter;
			ELSE
				lCurrentToken := cParseTokenError;
			END_IF

			lParsePtr := lParsePtr + 1;	

			bytePtr^ := 0;
			getNextToken := lCurrentToken;			
			parseDebug(getNextToken,tokenPtr);		
			RETURN;

		45: // -
			IF (length=0) THEN
				lCurrentToken := cParseTokenOption;
				lParsePtr := lParsePtr + 1;
				CONTINUE;
			END_IF
	END_CASE

	c := lParsePtr^;

	// not alphanumeric	or -_.:
	IF (NOT(((c>=48) AND (c<=57)) OR
		((c>=65) AND (c<=90)) OR
		((c>=97) AND (c<=122)) OR
		(c=45) OR
		(c=46) OR
		(c=58) OR
		(c=95))) THEN
		lParsePtr := lParsePtr + 1;
		CONTINUE;	
	END_IF

	IF (length>=INT_TO_UINT(SIZEOF(t_fqtoken_string)-1)) THEN
		lCurrentToken := cParseTokenOverflow;

		lParsePtr := lParsePtr + 1;

		bytePtr^ := 0;
		getNextToken := lCurrentToken;			
		parseDebug(getNextToken,tokenPtr);		
		RETURN;
	END_IF

	bytePtr^ := lParsePtr^;

	bytePtr := bytePtr + 1;
	lParsePtr := lParsePtr + 1;
	length := length + 1;
END_WHILE

IF (length=0) THEN
	lCurrentToken := cParseTokenFinished;
END_IF			

bytePtr^ := 0;
getNextToken := lCurrentToken;			
parseDebug(getNextToken,tokenPtr);

IF (NOT(lParseDebug)) THEN
	RETURN;
END_IF

append('debug - found token <');
append(tokenPtr^);
append('> of type <');
append(getStringForParseTokenType(tokenType));
append('>');
newline();

IF (NOT(__ISVALIDREF(stream))) THEN
	equals := FALSE;
	RETURN;	
END_IF

IF (stream.Length<>Length) THEN
	equals := FALSE;
	RETURN;
END_IF

equals := MEMUtils.MemCmp(stream.Buffer,ADR(lBuffer[0]),UINT_TO_DWORD(lLength));

IF (buffer=0) THEN
	RETURN;	
END_IF

MEMUtils.MemCpy(ADR(lBuffer[0]),buffer,UINT_TO_DWORD(stream.Length));

lLength := stream.Length;
lCharacters := stream.Characters;

FOR i:=0 TO cBufferSize DO
	IF (lBuffer[i] = 0) THEN
		lLength := i;

		IF (i>0) THEN
			lCharacters := lLength - 1;
		ELSE
			lCharacters := 0;			
		END_IF

		RETURN;
	END_IF
END_FOR

