ptr := __NEW(t_long_string);
_countLongString := _countLongString + 1;

IF (ptr=0) THEN
	gCodeErrorHandler(pMessage:='Memory allocation failed for <t_my_string>');
	allocateLongString REF= _defaultLongString;
	RETURN;
END_IF

ptr^ := concat('allocated:',UINT_TO_STRING(_countLongString));
allocateLongString REF= ptr^;

index := INT_TO_USINT(option);

IF ((index>lEnumOptionMax) OR
	(ptrptr=0)) THEN
	lFailed := TRUE;
	RETURN;
END_IF

IF (ptrptr[index]=0) THEN
	gCodeErrorHandler(pMessage:='EnumRegister option already registered - check for duplicates');
	lFailed := TRUE;
	RETURN;
END_IF

ptr := __NEW(t_enum_option_definition);

IF (ptr=0) THEN
	gCodeErrorHandler(pMessage:='Memory allocation failed for enum option in <TypeHandlerEnum>');
	lFailed := TRUE;
	RETURN;
END_IF

ptrptr[index] := ptr;

ptrptr[index]^.option := option;
ptrptr[index]^.token := token;
ptrptr[index]^.description := description;

