IF (handler=0) THEN
	RETURN;
END_IF

index := handler^.Definition.option;

IF ((index>cEnumRegisterMax) OR
	(index<0)) THEN
	gCodeErrorHandler(pMessage:='EnumRegister definition out of bounds');
	RETURN;
END_IF

IF ((lEnumRegister[index]<>0) AND
	(lEnumRegister[index]<>handler)) THEN
	gCodeErrorHandler(pMessage:='EnumRegister already registered');
	RETURN;
END_IF

IF (lEnumRegister[index]=0) THEN
	lEnumRegister[index] := handler;
END_IF

handler^.initialize();

IF ((enumType<=0) OR
	(enumType>cEnumRegisterMax)) THEN
	getTokenForEnum := 'illegal';
	RETURN;
END_IF

getTokenForEnum := lEnumRegister[enumType].getToken(value);

IF ((enumType>cEnumRegisterMax) OR
	(enumType<=0)) THEN

	getEnumFromToken := FALSE;

	RETURN;
END_IF

getEnumFromToken := lEnumRegister[enumType].getValue(token,target);

IF ((enumType<=0) OR
	(enumType>cEnumRegisterMax)) THEN
	getTokenForEnumType := 'illegal';
	RETURN;
END_IF

getTokenForEnumType := lEnumRegister[enumType].Definition.token;

IF ((enumType<=0) OR
	(enumType>cEnumRegisterMax)) THEN
	getStringForEnumOptions := '[]';
	RETURN;
END_IF

getStringForEnumOptions := lEnumRegister[enumType].getOptions();

IF ((strcmp(token,'true')) OR
	(strcmp(token,'TRUE'))) THEN
	target := TRUE;
	getValue := TRUE;
	RETURN;
END_IF

IF ((strcmp(token,'false')) OR
	(strcmp(token,'FALSE'))) THEN
	target := FALSE;
	getValue := TRUE;
	RETURN;
END_IF

getValue := FALSE;

IF (value) THEN
	getToken := 'true';
ELSE
	getToken := 'false';
END_IF

value := STRING_TO_DWORD(token);

getValue := strcmp(DWORD_TO_STRING(value),token);
IF (getValue) THEN
	target := value;
END_IF

value := STRING_TO_INT(token);

getValue := strcmp(INT_TO_STRING(value),token);
IF (getValue) THEN
	target := value;
END_IF

value := STRING_TO_REAL(token);

getValue := strcmp(REAL_TO_STRING(value),token);
IF (getValue) THEN
	target := value;
END_IF

