//	: t_medium_string:= 'value_type';
//	: t_medium_string:= 'meaning';

length := INT_TO_USINT(len(fqn));

count := 0;
position := 1;
currentLength := 0;

FOR i:=1 TO length DO
	IF (fqn[i-1]=46) THEN
		IF (count>=cTokenStringSetCount) THEN
			splitFQN := FALSE;
			RETURN;
		END_IF

		count := count + 1;
		tokens[count] := MID(fqn,currentLength,position);

		currentLength := 0;
		position := i + 1;
	ELSE
		currentLength := currentLength + 1;
		IF (currentLength>INT_TO_USINT(SIZEOF(t_token_string)-1)) THEN
			splitFQN := FALSE;
			RETURN;
		END_IF
	END_IF
END_FOR

IF (currentLength=0) THEN
	RETURN;
END_IF

IF (count>=cTokenStringSetCount) THEN
	splitFQN := FALSE;
	RETURN;
END_IF

count := count + 1;
tokens[count] := MID(fqn,currentLength,position);

splitFQN := TRUE;

FOR i:= 0 TO lEnumOptionMax DO
	IF (strcmp(token,lEnumOptions[i].token)) THEN
		getValue := TRUE;
		target := lEnumOptions[i].option;
		RETURN;
	END_IF
END_FOR

getValue := FALSE;

index := mapping(value);

IF (index>lEnumOptionMax) THEN
	getToken := 'illegal';
	RETURN;
END_IF

getToken := lEnumOptions[index].token;

index := mapping(option);

IF (index>cEnumOptionMax) THEN
	lFailed := TRUE;
	RETURN;
END_IF

lEnumOptionMax := MAX(lEnumOptionMax,index);

lEnumOptions[index].option := option;
lEnumOptions[index].token := token;
lEnumOptions[index].description := description;

IF (lDefinition.option=cEnumTypeChannelMask) THEN
	mapping := 0;

	CASE option OF
	cChannelNone:
		mapping := 0;

	cChannelUIRadio:
		mapping := 1;

	cChannelUICabin:
		mapping := 2;

	cChannelLogTCP:
		mapping := 3;

	cChannelUIRCache:
		mapping := 4;

	cChannelMaster:
		mapping := 5;

	cChannelEdgeLog:
		mapping := 6;

	cChannelEdgeStateMetric:
		mapping := 7;

	cChannelEdgeValueMetric:
		mapping := 8;

	cChannelEdgeTrace:
		mapping := 9;
	END_CASE

	RETURN;
END_IF

IF (lDefinition.option=cEnumTypeDebugMask) THEN
	mapping := 0;

	CASE option OF
	cDebugNone:
		mapping := 0;

	cDebugWaitForLog:
		mapping := 1;

	cDebugEnableFailSafeOnCrash:
		mapping := 2;

	cDebugDisableWatchdog:
		mapping := 3;

	cDebugSimulateCrash:
		mapping := 4;

	cDebugSimulateA:
		mapping := 5;

	cDebugSimulateB:
		mapping := 6;

	cDebugSimulateC:
		mapping := 7;
	END_CASE

	RETURN;
END_IF

mapping :=INT_TO_USINT(option);

str := '[';

FOR i:=0 TO lEnumOptionMax DO
	IF (first) THEN
		str := CONCAT(str,'"');
		first := FALSE;
	ELSE
		str := CONCAT(str,', "');
	END_IF

	str := CONCAT(str,lEnumOptions[i].token);
	str := CONCAT(str,'"');
END_FOR

str := CONCAT(str,']');

getOptions := str;
